INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 2, $dca$SINGLE$dca$::"QType", $dca$Which command initializes a new swarm and turns the current node into the first manager?$dca$, $dca$[{"id":"a","text":"docker swarm create"},{"id":"b","text":"docker swarm init"},{"id":"c","text":"docker node promote --init"},{"id":"d","text":"docker service create --swarm"}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$`docker swarm init` bootstraps a swarm and makes the current node a manager (leader). `docker swarm create` is not a valid subcommand; `docker node promote` operates on an existing swarm; `docker service create` deploys a service into an existing swarm.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/","label":"Docker Docs — Swarm mode overview"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which command initializes a new swarm and turns the current node into the first manager?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$In a swarm, you scale the `web` service to 5 replicas with `docker service scale web=5`. One worker node then goes down. What does the swarm do?$dca$, $dca$[{"id":"a","text":"It marks the service as failed until the node returns."},{"id":"b","text":"The orchestrator reschedules the lost replicas onto remaining healthy nodes to restore the desired count."},{"id":"c","text":"It permanently reduces the replica count to match available nodes."},{"id":"d","text":"Nothing — replicas are pinned to their original node."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$Swarm continuously reconciles actual state to the declared desired state. Lost replicas on a downed node are rescheduled onto healthy nodes. Replicas are not pinned unless constraints force them.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$In a swarm, you scale the `web` service to 5 replicas with `docker service scale web=5`. One worker node then goes down. What does the swarm do?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 3, $dca$MULTI$dca$::"QType", $dca$Select ALL true statements about swarm manager nodes and Raft.$dca$, $dca$[{"id":"a","text":"Manager nodes use the Raft consensus algorithm to maintain a consistent cluster state."},{"id":"b","text":"A swarm with 5 managers tolerates the loss of up to 2 managers while remaining functional."},{"id":"c","text":"Adding more managers always increases write throughput linearly."},{"id":"d","text":"An even number of managers does not improve fault tolerance over the next lower odd number."}]$dca$::jsonb, $dca$["a","b","d"]$dca$::jsonb, $dca$Raft requires a quorum (majority). With N managers, fault tolerance is floor((N-1)/2) — 5 managers tolerate 2 failures. More managers increase consensus overhead, not write throughput. An even count gives no tolerance benefit over the lower odd count, so odd numbers are recommended.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/raft/","label":"Docker Docs — Raft consensus in swarm mode"},{"url":"https://docs.docker.com/engine/swarm/admin_guide/","label":"Docker Docs — Administer and maintain a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Select ALL true statements about swarm manager nodes and Raft.$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 2, $dca$SINGLE$dca$::"QType", $dca$Which command deploys a multi-service application defined in `stack.yml` to a swarm as a stack named `app`?$dca$, $dca$[{"id":"a","text":"docker compose up -d stack.yml"},{"id":"b","text":"docker stack deploy -c stack.yml app"},{"id":"c","text":"docker service deploy --stack app stack.yml"},{"id":"d","text":"docker swarm deploy app stack.yml"}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$`docker stack deploy -c <compose-file> <stack-name>` deploys a Compose-format file to a swarm as a stack. `docker compose up` runs locally, not on a swarm; the other options are not valid commands.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/stack-deploy/","label":"Docker Docs — Deploy a stack to a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which command deploys a multi-service application defined in `stack.yml` to a swarm as a stack named `app`?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 4, $dca$SINGLE$dca$::"QType", $dca$You want a service to run exactly one task on every node in the swarm, including new nodes added later. Which service mode achieves this?$dca$, $dca$[{"id":"a","text":"Replicated mode with replicas equal to the current node count"},{"id":"b","text":"Global mode (--mode global)"},{"id":"c","text":"Replicated-job mode"},{"id":"d","text":"Constraint mode with node.role==worker"}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$A global service runs exactly one task per node and automatically schedules a task onto any node that joins later. A fixed replica count does not adjust when nodes are added; replicated-job runs to completion; constraints only filter placement.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$You want a service to run exactly one task on every node in the swarm, including new nodes added later. Which service mode achieves this?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Image Creation, Management, and Registry$dca$, 2, $dca$SINGLE$dca$::"QType", $dca$Which Dockerfile instruction defines the default command run by the container, while still allowing it to be overridden on `docker run`?$dca$, $dca$[{"id":"a","text":"ENTRYPOINT in exec form only"},{"id":"b","text":"CMD"},{"id":"c","text":"RUN"},{"id":"d","text":"EXEC"}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$`CMD` sets the default command/arguments and is fully overridden by arguments passed to `docker run`. `RUN` executes at build time; `EXEC` is not a Dockerfile instruction; `ENTRYPOINT` defines the executable and is not replaced by run-time args (they are appended).$dca$, $dca$[{"url":"https://docs.docker.com/reference/dockerfile/","label":"Docker Docs — Dockerfile reference"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which Dockerfile instruction defines the default command run by the container, while still allowing it to be overridden on `docker run`?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Image Creation, Management, and Registry$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$A multi-stage Dockerfile has a `build` stage with the Go toolchain and a final stage `FROM alpine`. What is the primary benefit?$dca$, $dca$[{"id":"a","text":"It builds faster because stages run in parallel by default."},{"id":"b","text":"The final image excludes build tooling and intermediate artifacts, drastically reducing image size and attack surface."},{"id":"c","text":"It allows the container to run as root automatically."},{"id":"d","text":"It removes the need for a .dockerignore file."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$Multi-stage builds copy only the needed artifacts into a lean final stage, so compilers/SDKs never ship in the runtime image. Stages are not parallel by default, and multi-stage has nothing to do with the run user or .dockerignore.$dca$, $dca$[{"url":"https://docs.docker.com/build/building/multi-stage/","label":"Docker Docs — Multi-stage builds"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$A multi-stage Dockerfile has a `build` stage with the Go toolchain and a final stage `FROM alpine`. What is the primary benefit?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Image Creation, Management, and Registry$dca$, 3, $dca$MULTI$dca$::"QType", $dca$Select ALL true statements about Docker image layers and tags.$dca$, $dca$[{"id":"a","text":"Each Dockerfile instruction such as RUN, COPY, or ADD creates a new image layer."},{"id":"b","text":"A tag is an immutable, content-addressable identifier that can never be moved."},{"id":"c","text":"Image layers are cached and reused across builds when the instruction and its inputs are unchanged."},{"id":"d","text":"A digest (sha256:...) uniquely and immutably identifies a specific image content."}]$dca$::jsonb, $dca$["a","c","d"]$dca$::jsonb, $dca$RUN/COPY/ADD create layers; the build cache reuses unchanged layers. A digest is the immutable content-addressable identifier — a tag is a mutable human-readable label that can be re-pointed to a different image.$dca$, $dca$[{"url":"https://docs.docker.com/build/building/best-practices/","label":"Docker Docs — Image layers and best practices"},{"url":"https://docs.docker.com/reference/cli/docker/image/tag/","label":"Docker Docs — docker image tag"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Select ALL true statements about Docker image layers and tags.$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Image Creation, Management, and Registry$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$You built `myapp:1.0` locally and want to push it to a private registry at `registry.example.com:5000`. Which sequence is correct?$dca$, $dca$[{"id":"a","text":"docker push myapp:1.0 registry.example.com:5000"},{"id":"b","text":"docker tag myapp:1.0 registry.example.com:5000/myapp:1.0 ; docker push registry.example.com:5000/myapp:1.0"},{"id":"c","text":"docker image export myapp:1.0 | docker registry import"},{"id":"d","text":"docker registry add myapp:1.0 ; docker push myapp:1.0"}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$An image must be tagged with the registry host/repository before pushing; `docker push` then targets that fully qualified reference. The other forms are not valid Docker CLI usage.$dca$, $dca$[{"url":"https://docs.docker.com/reference/cli/docker/image/push/","label":"Docker Docs — docker push"},{"url":"https://docs.docker.com/registry/","label":"Docker Docs — Docker registry"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$You built `myapp:1.0` locally and want to push it to a private registry at `registry.example.com:5000`. Which sequence is correct?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Installation and Configuration$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Which file is the canonical location for persistent Docker daemon configuration on Linux?$dca$, $dca$[{"id":"a","text":"/etc/docker/daemon.json"},{"id":"b","text":"/var/lib/docker/config.yml"},{"id":"c","text":"~/.docker/config.json"},{"id":"d","text":"/etc/default/docker-cli"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`/etc/docker/daemon.json` configures the daemon (`dockerd`). `~/.docker/config.json` is the *client* config (registry auth, etc.); `/var/lib/docker` is the data root, not config.$dca$, $dca$[{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which file is the canonical location for persistent Docker daemon configuration on Linux?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Installation and Configuration$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$You set `"log-driver": "json-file"` and `"log-opts": {"max-size": "10m", "max-file": "3"}` in daemon.json. What is the effect?$dca$, $dca$[{"id":"a","text":"All containers fail to start until logging is disabled."},{"id":"b","text":"New containers default to the json-file driver with log rotation capped at 3 files of 10 MB each."},{"id":"c","text":"Existing containers immediately switch drivers without restart."},{"id":"d","text":"Logs are forwarded to a remote syslog server."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$Daemon-level `log-driver`/`log-opts` set the default for newly created containers, with rotation here limited to three 10 MB files. Existing containers keep their original driver until recreated; syslog would require the `syslog` driver.$dca$, $dca$[{"url":"https://docs.docker.com/engine/logging/configure/","label":"Docker Docs — Configure logging drivers"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$You set `"log-driver": "json-file"` and `"log-opts": {"max-size": "10m", "max-file": "3"}` in daemon.json. What is the effect?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Installation and Configuration$dca$, 2, $dca$SINGLE$dca$::"QType", $dca$After editing /etc/docker/daemon.json on a systemd Linux host, which command applies the new daemon configuration?$dca$, $dca$[{"id":"a","text":"docker reload"},{"id":"b","text":"systemctl restart docker"},{"id":"c","text":"docker daemon --refresh"},{"id":"d","text":"kill -1 dockerd && docker start"}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$Restarting the service with `systemctl restart docker` reloads daemon.json. Some options can be reloaded with `SIGHUP` to dockerd, but there is no `docker reload`/`docker daemon --refresh` command.$dca$, $dca$[{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$After editing /etc/docker/daemon.json on a systemd Linux host, which command applies the new daemon configuration?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Networking$dca$, 2, $dca$SINGLE$dca$::"QType", $dca$What is the default network driver used when you run a container without specifying `--network`?$dca$, $dca$[{"id":"a","text":"host"},{"id":"b","text":"bridge"},{"id":"c","text":"overlay"},{"id":"d","text":"none"}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$On a standalone Docker host, containers attach to the default `bridge` network unless `--network` specifies otherwise. `overlay` is for multi-host swarm networking; `host` shares the host stack; `none` disables networking.$dca$, $dca$[{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"},{"url":"https://docs.docker.com/engine/network/drivers/bridge/","label":"Docker Docs — Bridge network driver"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$What is the default network driver used when you run a container without specifying `--network`?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Networking$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Two containers on a user-defined bridge network need to reach each other by name. What enables this?$dca$, $dca$[{"id":"a","text":"You must publish ports with -p for them to communicate."},{"id":"b","text":"Docker provides automatic DNS-based service discovery between containers on the same user-defined network."},{"id":"c","text":"They can only communicate via their IP addresses; no name resolution exists."},{"id":"d","text":"You must link them with the deprecated --link flag."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$User-defined bridge networks include an embedded DNS server so containers resolve each other by name/alias automatically. Port publishing is for host-to-container access; the legacy `--link` is not required on user-defined networks.$dca$, $dca$[{"url":"https://docs.docker.com/engine/network/drivers/bridge/","label":"Docker Docs — Bridge network driver"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Two containers on a user-defined bridge network need to reach each other by name. What enables this?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Networking$dca$, 4, $dca$MULTI$dca$::"QType", $dca$Select ALL true statements about Docker network drivers.$dca$, $dca$[{"id":"a","text":"The overlay driver connects multiple Docker daemons and is used for swarm service networking."},{"id":"b","text":"The macvlan driver assigns containers a MAC address making them appear as physical devices on the network."},{"id":"c","text":"The host driver gives a container its own isolated network namespace separate from the host."},{"id":"d","text":"Publishing a port with -p 8080:80 maps host port 8080 to container port 80."}]$dca$::jsonb, $dca$["a","b","d"]$dca$::jsonb, $dca$Overlay spans hosts (swarm); macvlan exposes containers as first-class L2 devices; `-p host:container` maps ports. The host driver does the opposite of option C — it removes network isolation by sharing the host network namespace.$dca$, $dca$[{"url":"https://docs.docker.com/engine/network/drivers/overlay/","label":"Docker Docs — Overlay network driver"},{"url":"https://docs.docker.com/engine/network/drivers/macvlan/","label":"Docker Docs — Macvlan network driver"},{"url":"https://docs.docker.com/engine/network/drivers/host/","label":"Docker Docs — Host network driver"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Select ALL true statements about Docker network drivers.$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Security$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Enabling Docker Content Trust (DOCKER_CONTENT_TRUST=1) provides what guarantee?$dca$, $dca$[{"id":"a","text":"It encrypts all container filesystem layers at rest."},{"id":"b","text":"It ensures images are signed and verifies their integrity and publisher before pull/run."},{"id":"c","text":"It scans images for CVEs and blocks vulnerable ones."},{"id":"d","text":"It forces all containers to run as a non-root user."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$Content trust uses digital signatures (Notary/TUF) so the engine only pulls/runs signed, verified images. It does not encrypt layers, scan for CVEs, or change the container user.$dca$, $dca$[{"url":"https://docs.docker.com/engine/security/trust/","label":"Docker Docs — Content trust"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Enabling Docker Content Trust (DOCKER_CONTENT_TRUST=1) provides what guarantee?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Security$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Which `docker run` flag drops all Linux capabilities and then adds back only NET_BIND_SERVICE?$dca$, $dca$[{"id":"a","text":"--privileged --cap NET_BIND_SERVICE"},{"id":"b","text":"--cap-drop ALL --cap-add NET_BIND_SERVICE"},{"id":"c","text":"--security-opt cap=NET_BIND_SERVICE"},{"id":"d","text":"--no-caps --add-cap NET_BIND_SERVICE"}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$`--cap-drop ALL` removes every capability and `--cap-add NET_BIND_SERVICE` re-grants only that one — a least-privilege pattern. `--privileged` does the opposite (grants everything); the other flags are not valid.$dca$, $dca$[{"url":"https://docs.docker.com/reference/cli/docker/container/run/#privileged","label":"Docker Docs — Runtime privilege and Linux capabilities"},{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which `docker run` flag drops all Linux capabilities and then adds back only NET_BIND_SERVICE?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Security$dca$, 4, $dca$SINGLE$dca$::"QType", $dca$You enable user namespace remapping (userns-remap) on the daemon. What is the security benefit?$dca$, $dca$[{"id":"a","text":"Containers can no longer use any volumes."},{"id":"b","text":"A process running as root (UID 0) inside a container is mapped to an unprivileged UID on the host."},{"id":"c","text":"It encrypts inter-container traffic automatically."},{"id":"d","text":"It disables the Docker API socket."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$userns-remap maps in-container UIDs (including root) to a non-privileged range on the host, so a container breakout does not yield host root. It does not disable volumes, encrypt traffic, or disable the API.$dca$, $dca$[{"url":"https://docs.docker.com/engine/security/userns-remap/","label":"Docker Docs — Isolate containers with a user namespace"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$You enable user namespace remapping (userns-remap) on the daemon. What is the security benefit?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Storage and Volumes$dca$, 2, $dca$SINGLE$dca$::"QType", $dca$Which statement best distinguishes a named volume from a bind mount?$dca$, $dca$[{"id":"a","text":"Named volumes are managed by Docker under its data root; bind mounts map an arbitrary host path you control directly."},{"id":"b","text":"Bind mounts are stored inside the container writable layer; volumes are not."},{"id":"c","text":"Named volumes can only be used in swarm mode."},{"id":"d","text":"Bind mounts are automatically backed up by Docker; volumes are not."}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$Volumes live in a Docker-managed area (e.g. /var/lib/docker/volumes) and are the preferred mechanism; bind mounts attach a specific host directory/file. Neither is stored in the container writable layer, and Docker does not auto-backup either.$dca$, $dca$[{"url":"https://docs.docker.com/engine/storage/volumes/","label":"Docker Docs — Volumes"},{"url":"https://docs.docker.com/engine/storage/bind-mounts/","label":"Docker Docs — Bind mounts"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which statement best distinguishes a named volume from a bind mount?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Storage and Volumes$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$You want sensitive scratch data to exist only in memory and never be written to the container or host disk. Which mount type fits?$dca$, $dca$[{"id":"a","text":"A named volume"},{"id":"b","text":"A bind mount"},{"id":"c","text":"A tmpfs mount"},{"id":"d","text":"The container writable layer"}]$dca$::jsonb, $dca$["c"]$dca$::jsonb, $dca$A tmpfs mount stores data in host RAM only and is removed when the container stops — ideal for transient secrets. Volumes and bind mounts persist on disk; the writable layer also persists for the container lifetime and can be committed.$dca$, $dca$[{"url":"https://docs.docker.com/engine/storage/tmpfs/","label":"Docker Docs — tmpfs mounts"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$You want sensitive scratch data to exist only in memory and never be written to the container or host disk. Which mount type fits?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 2, $dca$SINGLE$dca$::"QType", $dca$Which command promotes an existing worker node named `node-3` to a manager?$dca$, $dca$[{"id":"a","text":"docker node promote node-3"},{"id":"b","text":"docker swarm promote node-3"},{"id":"c","text":"docker node update --role manager node-3 --force"},{"id":"d","text":"docker manager add node-3"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`docker node promote <node>` (a shortcut for `docker node update --role manager`) elevates a worker to manager. `docker swarm promote` and `docker manager add` are not valid subcommands.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/manage-nodes/","label":"Docker Docs — Manage nodes in a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which command promotes an existing worker node named `node-3` to a manager?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$A swarm service is created with `--replicas 3`. You run `docker service ps web` and see one task in state `Shutdown` and a replacement `Running`. What happened?$dca$, $dca$[{"id":"a","text":"The service was scaled down to 2 replicas."},{"id":"b","text":"A task failed or its node became unavailable, so the orchestrator created a replacement to maintain the desired 3 running tasks."},{"id":"c","text":"The whole service crashed and must be redeployed."},{"id":"d","text":"Docker keeps every task ever created in the Running state."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$Swarm keeps a task history; a Shutdown task plus a new Running task means the original task ended and was rescheduled to keep the declared replica count. The service itself is healthy and was not scaled down.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$A swarm service is created with `--replicas 3`. You run `docker service ps web` and see one task in state `Shutdown` and a replacement `Running`. What happened?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Which `docker service create` flag publishes container port 80 on swarm port 8080 using the routing mesh?$dca$, $dca$[{"id":"a","text":"--expose 8080:80"},{"id":"b","text":"--publish published=8080,target=80"},{"id":"c","text":"--port 8080:80 --mesh"},{"id":"d","text":"--ingress 8080:80"}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$`--publish published=8080,target=80` (or `-p 8080:80`) publishes the port through the swarm routing mesh by default (ingress mode). `--expose` only documents a port; the other flags are not valid.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/ingress/","label":"Docker Docs — Use swarm mode routing mesh"},{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which `docker service create` flag publishes container port 80 on swarm port 8080 using the routing mesh?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$You want a swarm service to publish a port but bypass the routing mesh so each node only answers when it runs a task locally. Which publish mode achieves this?$dca$, $dca$[{"id":"a","text":"mode=ingress"},{"id":"b","text":"mode=host"},{"id":"c","text":"mode=global"},{"id":"d","text":"mode=direct"}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$`--publish mode=host` binds the port directly on the node running the task, skipping the routing mesh. `mode=ingress` is the default mesh behavior; `global`/`direct` are not publish modes.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/ingress/","label":"Docker Docs — Use swarm mode routing mesh"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$You want a swarm service to publish a port but bypass the routing mesh so each node only answers when it runs a task locally. Which publish mode achieves this?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 2, $dca$SINGLE$dca$::"QType", $dca$Which command removes a stack named `app` and all of its services, networks, and configs from the swarm?$dca$, $dca$[{"id":"a","text":"docker stack rm app"},{"id":"b","text":"docker stack down app"},{"id":"c","text":"docker swarm rm app"},{"id":"d","text":"docker service rm app"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`docker stack rm app` deletes every resource that stack created. There is no `docker stack down`; `docker service rm` only removes a single service, not the whole stack.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/stack-deploy/","label":"Docker Docs — Deploy a stack to a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which command removes a stack named `app` and all of its services, networks, and configs from the swarm?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 4, $dca$MULTI$dca$::"QType", $dca$Select ALL true statements about swarm service rollbacks and health.$dca$, $dca$[{"id":"a","text":"docker service rollback reverts a service to its previous specification."},{"id":"b","text":"A --update-failure-action rollback can automatically roll back an update when too many tasks fail."},{"id":"c","text":"A container HEALTHCHECK status of unhealthy can cause swarm to replace the task during an update."},{"id":"d","text":"Rollbacks are impossible once an update completes."}]$dca$::jsonb, $dca$["a","b","c"]$dca$::jsonb, $dca$Swarm stores the prior service spec so `docker service rollback` and `--update-failure-action rollback` work; healthchecks feed update decisions. Rollback to the previous spec remains available after an update completes, so D is false.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"},{"url":"https://docs.docker.com/engine/swarm/admin_guide/","label":"Docker Docs — Administer and maintain a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Select ALL true statements about swarm service rollbacks and health.$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$A node shows `Availability: Active` but `Status: Down` in `docker node ls`. What does this indicate?$dca$, $dca$[{"id":"a","text":"The node is intentionally drained."},{"id":"b","text":"The manager has lost contact with the node (it is unreachable/offline) even though it is configured to accept tasks."},{"id":"c","text":"The node has been removed from the swarm."},{"id":"d","text":"The node is paused for maintenance."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$`Availability=Active` means it should accept tasks, but `Status=Down` means the manager cannot reach it, so its tasks are rescheduled elsewhere. Drain/pause are availability values, not the Down status.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/manage-nodes/","label":"Docker Docs — Manage nodes in a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$A node shows `Availability: Active` but `Status: Down` in `docker node ls`. What does this indicate?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Which command scales the swarm service `api` to 10 replicas?$dca$, $dca$[{"id":"a","text":"docker service scale api=10"},{"id":"b","text":"docker scale api 10"},{"id":"c","text":"docker service replicas api 10"},{"id":"d","text":"docker swarm scale api=10"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`docker service scale api=10` (or `docker service update --replicas 10 api`) sets the desired replica count. The other commands are not valid Docker CLI syntax.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which command scales the swarm service `api` to 10 replicas?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 2, $dca$TRUE_FALSE$dca$::"QType", $dca$True or False: Swarm mode is a separate product you must install in addition to the Docker Engine.$dca$, $dca$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":"Only on Windows"},{"id":"d","text":"Only with Docker Desktop"}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$False. Swarm mode is built into the Docker Engine; you simply run `docker swarm init` to enable it — no separate package or installation is required.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/","label":"Docker Docs — Swarm mode overview"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$True or False: Swarm mode is a separate product you must install in addition to the Docker Engine.$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 4, $dca$SINGLE$dca$::"QType", $dca$You want to back up the swarm so the cluster can be recovered if managers are lost. What should you back up on a manager?$dca$, $dca$[{"id":"a","text":"Only /var/lib/docker/volumes"},{"id":"b","text":"The /var/lib/docker/swarm directory (the Raft state/store), ideally with the daemon stopped"},{"id":"c","text":"The image cache under /var/lib/docker/overlay2"},{"id":"d","text":"The /etc/docker/daemon.json file alone"}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$The swarm Raft state and TLS material live under `/var/lib/docker/swarm`; backing it up (engine stopped for consistency) lets you restore the cluster. Volumes and image cache do not contain swarm cluster state.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/admin_guide/","label":"Docker Docs — Administer and maintain a swarm"},{"url":"https://docs.docker.com/engine/swarm/raft/","label":"Docker Docs — Raft consensus in swarm mode"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$You want to back up the swarm so the cluster can be recovered if managers are lost. What should you back up on a manager?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$A `docker stack deploy` Compose file uses the `deploy:` key with `replicas`, `placement`, and `resources`. Where are these honored?$dca$, $dca$[{"id":"a","text":"Only by docker compose up locally."},{"id":"b","text":"Only by swarm (docker stack deploy) — the deploy key is ignored by plain docker compose up."},{"id":"c","text":"By both, identically."},{"id":"d","text":"By the registry when pushing."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$The `deploy:` section is a swarm-specific directive applied by `docker stack deploy`; standalone `docker compose up` ignores it. It has nothing to do with registries.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/stack-deploy/","label":"Docker Docs — Deploy a stack to a swarm"},{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$A `docker stack deploy` Compose file uses the `deploy:` key with `replicas`, `placement`, and `resources`. Where are these honored?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Image Creation, Management, and Registry$dca$, 2, $dca$SINGLE$dca$::"QType", $dca$Which Dockerfile instruction sets environment variables that persist in the running container?$dca$, $dca$[{"id":"a","text":"ARG"},{"id":"b","text":"ENV"},{"id":"c","text":"SET"},{"id":"d","text":"EXPORT"}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$`ENV` defines variables available at build time and in the running container. `ARG` values are build-time only and not present at runtime; `SET`/`EXPORT` are not Dockerfile instructions.$dca$, $dca$[{"url":"https://docs.docker.com/reference/dockerfile/","label":"Docker Docs — Dockerfile reference"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which Dockerfile instruction sets environment variables that persist in the running container?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Image Creation, Management, and Registry$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$What is the difference between `ARG` and `ENV` in a Dockerfile?$dca$, $dca$[{"id":"a","text":"They are identical aliases."},{"id":"b","text":"ARG defines build-time variables (passed via --build-arg) not present at runtime; ENV sets variables available both at build time and in the running container."},{"id":"c","text":"ENV is build-time only; ARG is runtime only."},{"id":"d","text":"ARG can only be used in multi-stage builds."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$ARG values are supplied with `--build-arg` and only exist during the build; ENV values persist into the image and container environment. Both can be used in any build, single- or multi-stage.$dca$, $dca$[{"url":"https://docs.docker.com/reference/dockerfile/","label":"Docker Docs — Dockerfile reference"},{"url":"https://docs.docker.com/build/building/packaging/","label":"Docker Docs — Building images"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$What is the difference between `ARG` and `ENV` in a Dockerfile?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Image Creation, Management, and Registry$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Which command authenticates the Docker CLI to a registry so subsequent pushes/pulls are authorized?$dca$, $dca$[{"id":"a","text":"docker auth registry.example.com"},{"id":"b","text":"docker login registry.example.com"},{"id":"c","text":"docker registry login"},{"id":"d","text":"docker connect registry.example.com"}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$`docker login <registry>` stores credentials (in `~/.docker/config.json` or a credential helper) for that registry. `docker auth`/`docker connect`/`docker registry login` are not valid commands.$dca$, $dca$[{"url":"https://docs.docker.com/registry/","label":"Docker Docs — Docker registry"},{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which command authenticates the Docker CLI to a registry so subsequent pushes/pulls are authorized?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Image Creation, Management, and Registry$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$You want to inspect the build history and layer commands of an image `myapp:1.0`. Which command shows this?$dca$, $dca$[{"id":"a","text":"docker image history myapp:1.0"},{"id":"b","text":"docker image layers myapp:1.0"},{"id":"c","text":"docker inspect --layers myapp:1.0"},{"id":"d","text":"docker build --show-history myapp:1.0"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`docker image history` (or `docker history`) lists the layers and the instruction that created each. `docker inspect` shows config/metadata but not the per-layer build commands the way history does; the others are not valid.$dca$, $dca$[{"url":"https://docs.docker.com/build/building/best-practices/","label":"Docker Docs — Image layers and best practices"},{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$You want to inspect the build history and layer commands of an image `myapp:1.0`. Which command shows this?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Image Creation, Management, and Registry$dca$, 4, $dca$MULTI$dca$::"QType", $dca$Select ALL true statements about Docker registries and image references.$dca$, $dca$[{"id":"a","text":"An image reference has the form [registry[:port]/]repository[:tag|@digest]."},{"id":"b","text":"If no registry is specified, the Docker CLI defaults to Docker Hub (docker.io)."},{"id":"c","text":"docker push always pushes to the local daemon only."},{"id":"d","text":"An insecure (HTTP) registry must be allowed via the insecure-registries daemon setting."}]$dca$::jsonb, $dca$["a","b","d"]$dca$::jsonb, $dca$References include an optional registry and a tag or digest; an omitted registry defaults to docker.io; HTTP registries require the `insecure-registries` allowlist. `docker push` sends the image to a remote registry, not the local daemon, so C is false.$dca$, $dca$[{"url":"https://docs.docker.com/registry/","label":"Docker Docs — Docker registry"},{"url":"https://docs.docker.com/reference/cli/docker/image/push/","label":"Docker Docs — docker push"},{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Select ALL true statements about Docker registries and image references.$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Image Creation, Management, and Registry$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Which command saves the image `myapp:1.0` to a portable tar archive that can be loaded on an air-gapped host?$dca$, $dca$[{"id":"a","text":"docker export myapp:1.0 > myapp.tar"},{"id":"b","text":"docker save -o myapp.tar myapp:1.0"},{"id":"c","text":"docker commit myapp:1.0 myapp.tar"},{"id":"d","text":"docker image archive myapp:1.0"}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$`docker save` writes one or more images (with all layers/metadata) to a tar that `docker load` can import. `docker export` dumps a container filesystem (not an image with history); `docker commit` creates an image from a container.$dca$, $dca$[{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"},{"url":"https://docs.docker.com/build/building/best-practices/","label":"Docker Docs — Image layers and best practices"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which command saves the image `myapp:1.0` to a portable tar archive that can be loaded on an air-gapped host?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Image Creation, Management, and Registry$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$A HEALTHCHECK instruction in a Dockerfile primarily lets Docker:$dca$, $dca$[{"id":"a","text":"Sign the image so only trusted versions run."},{"id":"b","text":"Periodically run a command inside the container to report its health (healthy/unhealthy) so orchestrators can act on it."},{"id":"c","text":"Scan the image for CVEs at build time."},{"id":"d","text":"Reduce the number of layers in the image."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$HEALTHCHECK defines a probe whose exit status sets the container health state, which swarm and tooling use for replacement/routing. It does not sign, scan, or change layering.$dca$, $dca$[{"url":"https://docs.docker.com/reference/dockerfile/","label":"Docker Docs — Dockerfile reference"},{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$A HEALTHCHECK instruction in a Dockerfile primarily lets Docker:$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Image Creation, Management, and Registry$dca$, 2, $dca$TRUE_FALSE$dca$::"QType", $dca$True or False: Running `docker image prune` (without -a) removes all unused images, including tagged ones not used by any container.$dca$, $dca$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":"Only with --volumes"},{"id":"d","text":"Only in swarm mode"}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$False. `docker image prune` removes only dangling images (untagged, no repository). You must add `-a`/`--all` to also remove unused but tagged images.$dca$, $dca$[{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"},{"url":"https://docs.docker.com/build/building/best-practices/","label":"Docker Docs — Image layers and best practices"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$True or False: Running `docker image prune` (without -a) removes all unused images, including tagged ones not used by any container.$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Image Creation, Management, and Registry$dca$, 4, $dca$SINGLE$dca$::"QType", $dca$You build for both linux/amd64 and linux/arm64 and want a single tag clients can pull on either architecture. What Docker feature provides this?$dca$, $dca$[{"id":"a","text":"A manifest list / multi-architecture image built with docker buildx"},{"id":"b","text":"A multi-stage build"},{"id":"c","text":"The .dockerignore file"},{"id":"d","text":"Docker Content Trust"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$A manifest list (multi-arch image), typically produced with `docker buildx build --platform`, lets one tag resolve to the right per-architecture image automatically. Multi-stage builds, .dockerignore, and content trust solve unrelated problems.$dca$, $dca$[{"url":"https://docs.docker.com/build/building/packaging/","label":"Docker Docs — Building images"},{"url":"https://docs.docker.com/build/building/multi-stage/","label":"Docker Docs — Multi-stage builds"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$You build for both linux/amd64 and linux/arm64 and want a single tag clients can pull on either architecture. What Docker feature provides this?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Installation and Configuration$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Which daemon.json key sets the default cgroup/OCI runtime, and what is the conventional default runtime name?$dca$, $dca$[{"id":"a","text":"\"default-runtime\": \"runc\""},{"id":"b","text":"\"oci-runtime\": \"containerd\""},{"id":"c","text":"\"runtime\": \"docker\""},{"id":"d","text":"\"exec-runtime\": \"runc\""}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$The `default-runtime` key chooses which OCI runtime new containers use; the conventional default is `runc`. The other keys are not valid daemon configuration options.$dca$, $dca$[{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which daemon.json key sets the default cgroup/OCI runtime, and what is the conventional default runtime name?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Installation and Configuration$dca$, 2, $dca$SINGLE$dca$::"QType", $dca$Which command displays disk usage by images, containers, volumes, and build cache?$dca$, $dca$[{"id":"a","text":"docker system df"},{"id":"b","text":"docker disk usage"},{"id":"c","text":"docker info --disk"},{"id":"d","text":"docker volume df"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`docker system df` summarizes space used (and reclaimable) by images, containers, local volumes, and build cache. The other commands are not valid.$dca$, $dca$[{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"},{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which command displays disk usage by images, containers, volumes, and build cache?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Installation and Configuration$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$A container exits immediately and you want it to restart automatically unless you explicitly stop it, surviving daemon restarts. Which restart policy fits?$dca$, $dca$[{"id":"a","text":"--restart no"},{"id":"b","text":"--restart on-failure:3"},{"id":"c","text":"--restart unless-stopped"},{"id":"d","text":"--restart=once"}]$dca$::jsonb, $dca$["c"]$dca$::jsonb, $dca$`unless-stopped` restarts the container automatically (including after daemon/host reboot) unless it was explicitly stopped. `on-failure:3` caps retries and only on non-zero exit; `--restart=once` is not a valid policy.$dca$, $dca$[{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"},{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$A container exits immediately and you want it to restart automatically unless you explicitly stop it, surviving daemon restarts. Which restart policy fits?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Installation and Configuration$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$After adding your user to the `docker` group, why can that user run Docker without sudo, and what is the security caveat?$dca$, $dca$[{"id":"a","text":"It does not work; sudo is always required."},{"id":"b","text":"The docker group grants access to the Docker daemon socket, which is root-equivalent — group membership effectively grants root on the host."},{"id":"c","text":"It only allows read-only Docker commands."},{"id":"d","text":"It encrypts the Docker socket for that user."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$Members of the `docker` group can talk to the daemon socket, and the Docker API is root-equivalent (mount host paths, run privileged containers). Treat docker-group membership as granting root.$dca$, $dca$[{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"},{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$After adding your user to the `docker` group, why can that user run Docker without sudo, and what is the security caveat?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Installation and Configuration$dca$, 2, $dca$SINGLE$dca$::"QType", $dca$Which command streams real-time resource usage (CPU, memory, network, block I/O) for running containers?$dca$, $dca$[{"id":"a","text":"docker stats"},{"id":"b","text":"docker top"},{"id":"c","text":"docker metrics"},{"id":"d","text":"docker monitor"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`docker stats` shows a live stream of per-container CPU/memory/network/IO usage. `docker top` lists processes inside one container; `docker metrics`/`docker monitor` are not commands.$dca$, $dca$[{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which command streams real-time resource usage (CPU, memory, network, block I/O) for running containers?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Installation and Configuration$dca$, 3, $dca$MULTI$dca$::"QType", $dca$Select ALL valid daemon.json configuration keys.$dca$, $dca$[{"id":"a","text":"\"insecure-registries\""},{"id":"b","text":"\"registry-mirrors\""},{"id":"c","text":"\"default-address-pools\""},{"id":"d","text":"\"auto-prune-everything\""}]$dca$::jsonb, $dca$["a","b","c"]$dca$::jsonb, $dca$`insecure-registries`, `registry-mirrors`, and `default-address-pools` are real daemon options (HTTP registries, pull-through mirrors, and the address ranges for new bridge/overlay networks). `auto-prune-everything` is not a Docker daemon key.$dca$, $dca$[{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"},{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Select ALL valid daemon.json configuration keys.$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Installation and Configuration$dca$, 4, $dca$SINGLE$dca$::"QType", $dca$You add `"registry-mirrors": ["https://mirror.example.com"]` to daemon.json. What is the effect?$dca$, $dca$[{"id":"a","text":"All pushes go to mirror.example.com."},{"id":"b","text":"Docker Hub pulls are first attempted through the configured pull-through mirror, reducing rate limits and latency."},{"id":"c","text":"It disables Docker Hub entirely."},{"id":"d","text":"It signs images automatically."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$A registry mirror is a pull-through cache for Docker Hub: pulls try the mirror first. It does not affect pushes, does not disable Hub, and does not sign images.$dca$, $dca$[{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"},{"url":"https://docs.docker.com/registry/","label":"Docker Docs — Docker registry"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$You add `"registry-mirrors": ["https://mirror.example.com"]` to daemon.json. What is the effect?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Networking$dca$, 2, $dca$SINGLE$dca$::"QType", $dca$Which command lists all networks the Docker daemon manages?$dca$, $dca$[{"id":"a","text":"docker network ls"},{"id":"b","text":"docker net list"},{"id":"c","text":"docker network show"},{"id":"d","text":"docker ls networks"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`docker network ls` lists networks with their ID, name, driver, and scope. The other forms are not valid Docker CLI syntax.$dca$, $dca$[{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which command lists all networks the Docker daemon manages?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Networking$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$You attach a running container to an additional user-defined network after it started. Which command does this?$dca$, $dca$[{"id":"a","text":"docker network connect mynet mycontainer"},{"id":"b","text":"docker network add mycontainer mynet"},{"id":"c","text":"docker container network mycontainer mynet"},{"id":"d","text":"docker attach --network mynet mycontainer"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`docker network connect <network> <container>` attaches a running container to another network (and `docker network disconnect` removes it). The other commands are not valid.$dca$, $dca$[{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"},{"url":"https://docs.docker.com/engine/network/drivers/bridge/","label":"Docker Docs — Bridge network driver"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$You attach a running container to an additional user-defined network after it started. Which command does this?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Networking$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$A container run with `--network none` has what connectivity?$dca$, $dca$[{"id":"a","text":"Full access to the host network."},{"id":"b","text":"Only a loopback interface — no external network connectivity at all."},{"id":"c","text":"Access to the default bridge only."},{"id":"d","text":"Access to overlay networks only."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$The `none` driver gives the container its own network namespace with only loopback and no external interfaces — useful for fully isolated, network-free workloads.$dca$, $dca$[{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$A container run with `--network none` has what connectivity?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Networking$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Two containers must communicate, but you do NOT want them reachable from any other container on the host. The best approach is to:$dca$, $dca$[{"id":"a","text":"Put them both on the default bridge network."},{"id":"b","text":"Create a dedicated user-defined bridge network and attach only those two containers to it."},{"id":"c","text":"Use --network host for both."},{"id":"d","text":"Publish all their ports with -p."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$A dedicated user-defined network isolates the two containers (with DNS by name) from containers on other networks. The shared default bridge mixes all containers; host networking removes isolation; publishing ports exposes them more widely.$dca$, $dca$[{"url":"https://docs.docker.com/engine/network/drivers/bridge/","label":"Docker Docs — Bridge network driver"},{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Two containers must communicate, but you do NOT want them reachable from any other container on the host. The best approach is to:$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Networking$dca$, 4, $dca$MULTI$dca$::"QType", $dca$Select ALL true statements about swarm overlay networking.$dca$, $dca$[{"id":"a","text":"Overlay networks let services on different swarm nodes communicate as if on one L2 network."},{"id":"b","text":"Swarm overlay control plane traffic can be encrypted with the --opt encrypted flag on the network."},{"id":"c","text":"Containers not part of a service cannot ever join a swarm overlay network."},{"id":"d","text":"The overlay driver uses VXLAN encapsulation under the hood."}]$dca$::jsonb, $dca$["a","b","d"]$dca$::jsonb, $dca$Overlay spans nodes via VXLAN and supports optional data-plane encryption (`--opt encrypted`). Standalone containers CAN join an overlay if it is created `--attachable`, so C is false.$dca$, $dca$[{"url":"https://docs.docker.com/engine/network/drivers/overlay/","label":"Docker Docs — Overlay network driver"},{"url":"https://docs.docker.com/engine/swarm/","label":"Docker Docs — Swarm mode overview"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Select ALL true statements about swarm overlay networking.$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Networking$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Which command shows the IP address and network attachments of a running container `web`?$dca$, $dca$[{"id":"a","text":"docker inspect web (look at NetworkSettings)"},{"id":"b","text":"docker network ip web"},{"id":"c","text":"docker container ip web"},{"id":"d","text":"docker ps --ip web"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`docker inspect web` exposes `NetworkSettings`/`Networks` with the container IP, gateway, and attached networks (you can also use a `--format` template). The other commands are not valid.$dca$, $dca$[{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"},{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which command shows the IP address and network attachments of a running container `web`?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Networking$dca$, 4, $dca$SINGLE$dca$::"QType", $dca$You publish `-p 80:80` for two different containers on the same host at the same time. What happens to the second one?$dca$, $dca$[{"id":"a","text":"Both share port 80 transparently via the routing mesh."},{"id":"b","text":"The second container fails to start (or the run fails) because host port 80 is already bound."},{"id":"c","text":"Docker automatically remaps the second to a random port."},{"id":"d","text":"The first container is stopped to free the port."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$A published host port is exclusive on a standalone host, so binding the same port twice fails with a port-already-allocated error. Docker does not auto-remap or stop the existing container; the routing mesh applies to swarm services, not standalone `-p`.$dca$, $dca$[{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"},{"url":"https://docs.docker.com/engine/network/drivers/bridge/","label":"Docker Docs — Bridge network driver"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$You publish `-p 80:80` for two different containers on the same host at the same time. What happens to the second one?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Security$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Which `docker run` flag makes the container root filesystem read-only, forcing writable data into explicit volumes/tmpfs?$dca$, $dca$[{"id":"a","text":"--read-only"},{"id":"b","text":"--immutable"},{"id":"c","text":"--no-write"},{"id":"d","text":"--ro-rootfs"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`--read-only` mounts the container filesystem read-only; you then add `--tmpfs` or volumes for paths that must be writable. The other flags do not exist.$dca$, $dca$[{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"},{"url":"https://docs.docker.com/reference/cli/docker/container/run/#privileged","label":"Docker Docs — Runtime privilege and Linux capabilities"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which `docker run` flag makes the container root filesystem read-only, forcing writable data into explicit volumes/tmpfs?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Security$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$How are Docker swarm secrets exposed inside a container that the service is granted?$dca$, $dca$[{"id":"a","text":"As environment variables."},{"id":"b","text":"As in-memory files mounted under /run/secrets/<secret_name>."},{"id":"c","text":"Written to the image during build."},{"id":"d","text":"In the container labels."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$A granted secret is mounted as a tmpfs-backed file at `/run/secrets/<name>`, never persisted to disk or the image and not placed in env vars (which can leak via inspect/logs).$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/secrets/","label":"Docker Docs — Manage sensitive data with secrets"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$How are Docker swarm secrets exposed inside a container that the service is granted?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Security$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Which `docker run` flag prevents a process inside the container from gaining new privileges (e.g. via setuid binaries)?$dca$, $dca$[{"id":"a","text":"--security-opt no-new-privileges"},{"id":"b","text":"--cap-drop SETUID"},{"id":"c","text":"--privileged=false"},{"id":"d","text":"--no-setuid"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`--security-opt no-new-privileges` sets the kernel `no_new_privs` bit so setuid/setgid binaries cannot escalate privileges. Dropping SETUID alone is narrower; `--privileged=false` is just the default; `--no-setuid` is not a flag.$dca$, $dca$[{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"},{"url":"https://docs.docker.com/reference/cli/docker/container/run/#privileged","label":"Docker Docs — Runtime privilege and Linux capabilities"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which `docker run` flag prevents a process inside the container from gaining new privileges (e.g. via setuid binaries)?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Security$dca$, 2, $dca$TRUE_FALSE$dca$::"QType", $dca$True or False: By default, the root user inside a container (without userns-remap) is the same root (UID 0) as on the host.$dca$, $dca$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":"Only on Windows"},{"id":"d","text":"Only with --privileged"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$True. Without user-namespace remapping, container UID 0 maps to host UID 0; that is exactly why running as non-root and/or enabling userns-remap is recommended to limit breakout impact.$dca$, $dca$[{"url":"https://docs.docker.com/engine/security/userns-remap/","label":"Docker Docs — Isolate containers with a user namespace"},{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$True or False: By default, the root user inside a container (without userns-remap) is the same root (UID 0) as on the host.$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Security$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$You want to apply a custom AppArmor profile to a container. Which flag is used?$dca$, $dca$[{"id":"a","text":"--security-opt apparmor=my-profile"},{"id":"b","text":"--apparmor my-profile"},{"id":"c","text":"--lsm apparmor=my-profile"},{"id":"d","text":"--profile apparmor:my-profile"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`--security-opt apparmor=<profile>` selects the AppArmor profile for the container (Docker also loads a default `docker-default` profile). The other flag forms are not valid.$dca$, $dca$[{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"},{"url":"https://docs.docker.com/engine/security/seccomp/","label":"Docker Docs — Seccomp security profiles"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$You want to apply a custom AppArmor profile to a container. Which flag is used?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Security$dca$, 4, $dca$MULTI$dca$::"QType", $dca$Select ALL true statements about Docker Content Trust (DCT).$dca$, $dca$[{"id":"a","text":"Setting DOCKER_CONTENT_TRUST=1 makes docker pull only retrieve signed images."},{"id":"b","text":"DCT uses The Update Framework (TUF) / Notary for signing and verification."},{"id":"c","text":"With DCT enabled, docker push signs the pushed image."},{"id":"d","text":"DCT scans images for vulnerabilities before allowing them to run."}]$dca$::jsonb, $dca$["a","b","c"]$dca$::jsonb, $dca$DCT (Notary/TUF) signs on push and verifies signatures on pull/run when enabled. It is an integrity/publisher control, not a vulnerability scanner — that is a separate tool like Docker Scout.$dca$, $dca$[{"url":"https://docs.docker.com/engine/security/trust/","label":"Docker Docs — Content trust"},{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Select ALL true statements about Docker Content Trust (DCT).$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Security$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Why is mounting the host Docker socket (`-v /var/run/docker.sock:/var/run/docker.sock`) into a container a serious risk?$dca$, $dca$[{"id":"a","text":"It only slows the container down."},{"id":"b","text":"The container can then control the Docker daemon, which is root-equivalent, allowing full host compromise."},{"id":"c","text":"It disables container DNS."},{"id":"d","text":"It prevents the container from using volumes."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$A container with the daemon socket can create privileged containers and mount host paths, effectively gaining root on the host. Grant it only to trusted tooling and prefer scoped/proxied access.$dca$, $dca$[{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"},{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Why is mounting the host Docker socket (`-v /var/run/docker.sock:/var/run/docker.sock`) into a container a serious risk?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Storage and Volumes$dca$, 2, $dca$SINGLE$dca$::"QType", $dca$Which command removes all unused (dangling) local volumes to reclaim space?$dca$, $dca$[{"id":"a","text":"docker volume prune"},{"id":"b","text":"docker volume clean"},{"id":"c","text":"docker prune volumes"},{"id":"d","text":"docker volume rm --unused"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`docker volume prune` deletes local volumes not referenced by any container. The other commands are not valid Docker CLI syntax.$dca$, $dca$[{"url":"https://docs.docker.com/engine/storage/volumes/","label":"Docker Docs — Volumes"},{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which command removes all unused (dangling) local volumes to reclaim space?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Storage and Volumes$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Which `docker run` flag mounts a host directory `/data` into the container at `/app/data` as a bind mount using the --mount syntax?$dca$, $dca$[{"id":"a","text":"--mount type=bind,source=/data,target=/app/data"},{"id":"b","text":"--mount type=volume,source=/data,target=/app/data"},{"id":"c","text":"-v bind:/data:/app/data"},{"id":"d","text":"--bind /data:/app/data"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`--mount type=bind,source=/data,target=/app/data` is the explicit bind-mount form. `type=volume` would treat `/data` as a named volume; `-v bind:...` and `--bind` are not valid.$dca$, $dca$[{"url":"https://docs.docker.com/engine/storage/bind-mounts/","label":"Docker Docs — Bind mounts"},{"url":"https://docs.docker.com/engine/storage/volumes/","label":"Docker Docs — Volumes"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which `docker run` flag mounts a host directory `/data` into the container at `/app/data` as a bind mount using the --mount syntax?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Storage and Volumes$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$A volume driver/plugin (e.g. for NFS or cloud block storage) lets you:$dca$, $dca$[{"id":"a","text":"Only create volumes on the local disk."},{"id":"b","text":"Provision and attach volumes backed by external/remote storage systems so data survives node loss and can move between hosts."},{"id":"c","text":"Encrypt the image registry."},{"id":"d","text":"Replace the need for a Dockerfile."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$Volume plugins integrate external storage backends (NFS, cloud block/file storage), enabling portable, durable data across hosts — important for stateful services in a cluster. They are unrelated to registries or Dockerfiles.$dca$, $dca$[{"url":"https://docs.docker.com/engine/storage/volumes/","label":"Docker Docs — Volumes"},{"url":"https://docs.docker.com/engine/storage/drivers/","label":"Docker Docs — Storage drivers"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$A volume driver/plugin (e.g. for NFS or cloud block storage) lets you:$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Storage and Volumes$dca$, 4, $dca$SINGLE$dca$::"QType", $dca$You mount a named volume into a fresh container at a path that already contains files in the image. What happens on first use of an empty named volume?$dca$, $dca$[{"id":"a","text":"The image files at that path are deleted."},{"id":"b","text":"Docker copies the existing image content at the mount path into the new empty named volume (volume pre-population)."},{"id":"c","text":"The container fails to start."},{"id":"d","text":"The volume is ignored and the image files are used."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$For an empty named volume, Docker pre-populates it with the content already present at the mount target in the image. (This copy behavior does not apply to bind mounts or to non-empty volumes.)$dca$, $dca$[{"url":"https://docs.docker.com/engine/storage/volumes/","label":"Docker Docs — Volumes"},{"url":"https://docs.docker.com/engine/storage/bind-mounts/","label":"Docker Docs — Bind mounts"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P1$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$You mount a named volume into a fresh container at a path that already contains files in the image. What happens on first use of an empty named volume?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 2, $dca$SINGLE$dca$::"QType", $dca$Which command lists all nodes participating in a swarm (run from a manager)?$dca$, $dca$[{"id":"a","text":"docker swarm ls"},{"id":"b","text":"docker node ls"},{"id":"c","text":"docker service ps"},{"id":"d","text":"docker stack nodes"}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$`docker node ls` lists swarm nodes with their availability, manager status, and leader. `docker swarm ls` is not valid; `docker service ps` lists tasks of a service; there is no `docker stack nodes`.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/manage-nodes/","label":"Docker Docs — Manage nodes in a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which command lists all nodes participating in a swarm (run from a manager)?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$A swarm manager node is being decommissioned for maintenance. Which is the correct first step to safely move work off it without losing manager quorum?$dca$, $dca$[{"id":"a","text":"docker node rm <node> immediately"},{"id":"b","text":"docker node update --availability drain <node>"},{"id":"c","text":"docker swarm leave on that node while it is still the leader"},{"id":"d","text":"docker service scale all=0"}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$Setting availability to `drain` reschedules tasks off the node while keeping it in the swarm. Removing or leaving abruptly can break quorum; you demote and then remove managers carefully.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/manage-nodes/","label":"Docker Docs — Manage nodes in a swarm"},{"url":"https://docs.docker.com/engine/swarm/admin_guide/","label":"Docker Docs — Administer and maintain a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$A swarm manager node is being decommissioned for maintenance. Which is the correct first step to safely move work off it without losing manager quorum?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$How does the swarm routing mesh make a published service port reachable?$dca$, $dca$[{"id":"a","text":"Only the node currently running a task answers on the published port."},{"id":"b","text":"Every node in the swarm listens on the published port and routes the request to an active task, even if no task runs locally."},{"id":"c","text":"You must configure an external load balancer manually for any access."},{"id":"d","text":"The published port is reachable only from inside containers."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$The routing mesh makes the published port available on every swarm node; incoming traffic is load-balanced to a healthy task wherever it runs. An external LB is optional, not required.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/ingress/","label":"Docker Docs — Use swarm mode routing mesh"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$How does the swarm routing mesh make a published service port reachable?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$You create a swarm service that needs a database password. What is the recommended way to deliver it?$dca$, $dca$[{"id":"a","text":"Bake it into the image with ENV in the Dockerfile"},{"id":"b","text":"Pass it via --env on docker service create"},{"id":"c","text":"Create a Docker secret and attach it with --secret so it is mounted at /run/secrets"},{"id":"d","text":"Store it in a world-readable bind mount"}]$dca$::jsonb, $dca$["c"]$dca$::jsonb, $dca$Docker secrets are encrypted in the Raft log, transmitted only to nodes running the service, and exposed in-memory at /run/secrets. ENV/--env and bind mounts leak the value in image history, inspect output, or the filesystem.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/secrets/","label":"Docker Docs — Manage sensitive data with secrets"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$You create a swarm service that needs a database password. What is the recommended way to deliver it?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 4, $dca$MULTI$dca$::"QType", $dca$Select ALL true statements about Docker swarm services and stacks.$dca$, $dca$[{"id":"a","text":"docker service update --image newimage:tag triggers a rolling update of the service tasks."},{"id":"b","text":"Swarm configs (docker config) are intended for non-sensitive configuration files."},{"id":"c","text":"A stack deployed with docker stack deploy can include services, networks, and volumes from a single Compose file."},{"id":"d","text":"Worker nodes can run docker service create to schedule new services."}]$dca$::jsonb, $dca$["a","b","c"]$dca$::jsonb, $dca$Service updates roll out per the update config; configs hold non-secret data; stacks bundle services/networks/volumes. Only manager nodes accept orchestration commands like `service create` — workers cannot.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"},{"url":"https://docs.docker.com/engine/swarm/configs/","label":"Docker Docs — Store configuration data using configs"},{"url":"https://docs.docker.com/engine/swarm/stack-deploy/","label":"Docker Docs — Deploy a stack to a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Select ALL true statements about Docker swarm services and stacks.$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Image Creation, Management, and Registry$dca$, 2, $dca$SINGLE$dca$::"QType", $dca$Which Dockerfile instruction copies files from the build context and also supports remote URLs and automatic tar extraction?$dca$, $dca$[{"id":"a","text":"COPY"},{"id":"b","text":"ADD"},{"id":"c","text":"GET"},{"id":"d","text":"IMPORT"}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$`ADD` can fetch remote URLs and auto-extract local tar archives; `COPY` is the simpler, preferred instruction for plain file copies. `GET`/`IMPORT` are not Dockerfile instructions.$dca$, $dca$[{"url":"https://docs.docker.com/reference/dockerfile/","label":"Docker Docs — Dockerfile reference"},{"url":"https://docs.docker.com/build/building/best-practices/","label":"Docker Docs — Image layers and best practices"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which Dockerfile instruction copies files from the build context and also supports remote URLs and automatic tar extraction?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Image Creation, Management, and Registry$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$A teammate reports your image is huge because each RUN apt-get installs and then a later RUN deletes the cache. Why is the image still large?$dca$, $dca$[{"id":"a","text":"apt-get does not actually download anything."},{"id":"b","text":"Each RUN is a separate layer; files added in one layer still occupy space even if deleted in a later layer."},{"id":"c","text":"Docker compresses only the final layer."},{"id":"d","text":"The .dockerignore file overrides layer sizes."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$Layers are additive and immutable; deleting a file in a later layer hides it but its bytes remain in the earlier layer. Combine install + cleanup in a single RUN (or use multi-stage) to keep it out of the image.$dca$, $dca$[{"url":"https://docs.docker.com/build/building/best-practices/","label":"Docker Docs — Image layers and best practices"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$A teammate reports your image is huge because each RUN apt-get installs and then a later RUN deletes the cache. Why is the image still large?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Image Creation, Management, and Registry$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$What does `docker pull nginx@sha256:abc123...` guarantee compared to `docker pull nginx:latest`?$dca$, $dca$[{"id":"a","text":"It always pulls the newest build of nginx."},{"id":"b","text":"It pulls the exact, immutable image content identified by that digest regardless of tag movement."},{"id":"c","text":"It runs a vulnerability scan before pulling."},{"id":"d","text":"It pulls from Docker Hub only and never a private registry."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$Pinning by digest fetches the precise image content (reproducible/immutable). A tag like `latest` can be re-pointed at any time. Digest pinning does not scan images or restrict the registry.$dca$, $dca$[{"url":"https://docs.docker.com/reference/cli/docker/image/push/","label":"Docker Docs — docker push"},{"url":"https://docs.docker.com/reference/cli/docker/image/tag/","label":"Docker Docs — docker image tag"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$What does `docker pull nginx@sha256:abc123...` guarantee compared to `docker pull nginx:latest`?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Image Creation, Management, and Registry$dca$, 4, $dca$SINGLE$dca$::"QType", $dca$You run a local Docker registry with `docker run -d -p 5000:5000 registry:2`. To push `myapp` to it you should tag the image as:$dca$, $dca$[{"id":"a","text":"myapp:5000"},{"id":"b","text":"localhost:5000/myapp"},{"id":"c","text":"registry:2/myapp"},{"id":"d","text":"docker.io/library/myapp"}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$The registry host:port must prefix the repository, e.g. `localhost:5000/myapp`, before `docker push localhost:5000/myapp`. The other forms either lack the registry host or point at Docker Hub.$dca$, $dca$[{"url":"https://docs.docker.com/registry/","label":"Docker Docs — Docker registry"},{"url":"https://docs.docker.com/reference/cli/docker/image/push/","label":"Docker Docs — docker push"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$You run a local Docker registry with `docker run -d -p 5000:5000 registry:2`. To push `myapp` to it you should tag the image as:$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Installation and Configuration$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Which daemon.json setting changes where Docker stores images, containers, and volumes on disk?$dca$, $dca$[{"id":"a","text":"\"data-root\": \"/mnt/docker\""},{"id":"b","text":"\"graph-path\": \"/mnt/docker\""},{"id":"c","text":"\"storage-path\": \"/mnt/docker\""},{"id":"d","text":"\"root-dir\": \"/mnt/docker\""}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`data-root` (formerly the deprecated `graph`) sets the Docker data directory. The other keys are not valid daemon configuration options.$dca$, $dca$[{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which daemon.json setting changes where Docker stores images, containers, and volumes on disk?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Installation and Configuration$dca$, 2, $dca$SINGLE$dca$::"QType", $dca$Which command shows system-wide Docker information including the storage driver, logging driver, and number of containers/images?$dca$, $dca$[{"id":"a","text":"docker version"},{"id":"b","text":"docker info"},{"id":"c","text":"docker inspect docker"},{"id":"d","text":"docker system version"}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$`docker info` reports daemon-level details: storage/logging drivers, container and image counts, swarm status, etc. `docker version` shows client/server versions only.$dca$, $dca$[{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"},{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which command shows system-wide Docker information including the storage driver, logging driver, and number of containers/images?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Installation and Configuration$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$On Linux, which storage driver does Docker recommend and use by default on modern kernels with overlay filesystem support?$dca$, $dca$[{"id":"a","text":"aufs"},{"id":"b","text":"devicemapper"},{"id":"c","text":"overlay2"},{"id":"d","text":"vfs"}]$dca$::jsonb, $dca$["c"]$dca$::jsonb, $dca$`overlay2` is the recommended, default storage driver on supported Linux kernels. `aufs`/`devicemapper` are legacy; `vfs` has no copy-on-write and is used only for testing.$dca$, $dca$[{"url":"https://docs.docker.com/engine/storage/drivers/","label":"Docker Docs — Storage drivers"},{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$On Linux, which storage driver does Docker recommend and use by default on modern kernels with overlay filesystem support?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Networking$dca$, 2, $dca$SINGLE$dca$::"QType", $dca$Which command creates a user-defined overlay network named `appnet` for use by swarm services?$dca$, $dca$[{"id":"a","text":"docker network create -d overlay appnet"},{"id":"b","text":"docker network add overlay appnet"},{"id":"c","text":"docker swarm network create appnet"},{"id":"d","text":"docker overlay create appnet"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`docker network create -d overlay appnet` creates an attachable swarm-scoped overlay network. The other commands are not valid Docker CLI syntax.$dca$, $dca$[{"url":"https://docs.docker.com/engine/network/drivers/overlay/","label":"Docker Docs — Overlay network driver"},{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which command creates a user-defined overlay network named `appnet` for use by swarm services?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Networking$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$A container started with `--network host` behaves how with respect to port publishing?$dca$, $dca$[{"id":"a","text":"It still requires -p to expose ports."},{"id":"b","text":"It shares the host network namespace; the service binds directly to host ports and -p is ignored."},{"id":"c","text":"It cannot reach the network at all."},{"id":"d","text":"It gets its own IP on the default bridge."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$With the host driver the container uses the host network stack directly, so processes bind host ports without `-p` (which is ignored). There is no separate container IP or bridge attachment.$dca$, $dca$[{"url":"https://docs.docker.com/engine/network/drivers/host/","label":"Docker Docs — Host network driver"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$A container started with `--network host` behaves how with respect to port publishing?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Networking$dca$, 4, $dca$SINGLE$dca$::"QType", $dca$You want containers to appear as distinct physical hosts on the existing 192.168.10.0/24 LAN, each with its own LAN IP. Which network driver is designed for this?$dca$, $dca$[{"id":"a","text":"bridge"},{"id":"b","text":"overlay"},{"id":"c","text":"macvlan"},{"id":"d","text":"none"}]$dca$::jsonb, $dca$["c"]$dca$::jsonb, $dca$The macvlan driver attaches containers directly to the physical network with their own MAC/IP, making them appear as separate devices on the LAN. bridge NATs behind the host; overlay is multi-host swarm; none disables networking.$dca$, $dca$[{"url":"https://docs.docker.com/engine/network/drivers/macvlan/","label":"Docker Docs — Macvlan network driver"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$You want containers to appear as distinct physical hosts on the existing 192.168.10.0/24 LAN, each with its own LAN IP. Which network driver is designed for this?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Security$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$What does running a container with `--privileged` do?$dca$, $dca$[{"id":"a","text":"It drops all Linux capabilities for maximum isolation."},{"id":"b","text":"It grants the container nearly all host capabilities and device access, largely disabling isolation safeguards."},{"id":"c","text":"It forces the container to run as a non-root user."},{"id":"d","text":"It enables Docker Content Trust for that container."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$`--privileged` gives the container almost full host access (all capabilities, devices, relaxed seccomp/AppArmor). It is the opposite of least privilege and should be avoided unless strictly required.$dca$, $dca$[{"url":"https://docs.docker.com/reference/cli/docker/container/run/#privileged","label":"Docker Docs — Runtime privilege and Linux capabilities"},{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$What does running a container with `--privileged` do?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Security$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$By default Docker applies a seccomp profile to containers. What does this profile do?$dca$, $dca$[{"id":"a","text":"It encrypts the container root filesystem."},{"id":"b","text":"It restricts the set of Linux syscalls a container process may invoke, blocking dangerous ones by default."},{"id":"c","text":"It signs images on push."},{"id":"d","text":"It rotates container logs."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$Seccomp filters syscalls; Docker ships a default profile that blocks a large set of dangerous calls while allowing those most apps need. It is unrelated to encryption, signing, or logging.$dca$, $dca$[{"url":"https://docs.docker.com/engine/security/seccomp/","label":"Docker Docs — Seccomp security profiles"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$By default Docker applies a seccomp profile to containers. What does this profile do?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Security$dca$, 4, $dca$MULTI$dca$::"QType", $dca$Select ALL recommended Docker security hardening practices.$dca$, $dca$[{"id":"a","text":"Run containers as a non-root user where possible (USER instruction or --user)."},{"id":"b","text":"Use --cap-drop ALL and add back only required capabilities."},{"id":"c","text":"Run every container with --privileged for convenience."},{"id":"d","text":"Enable Docker Content Trust to only run signed images."}]$dca$::jsonb, $dca$["a","b","d"]$dca$::jsonb, $dca$Non-root users, dropping capabilities, and content trust all reduce risk. Running everything `--privileged` does the opposite — it removes isolation and is explicitly discouraged.$dca$, $dca$[{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"},{"url":"https://docs.docker.com/reference/cli/docker/container/run/#privileged","label":"Docker Docs — Runtime privilege and Linux capabilities"},{"url":"https://docs.docker.com/engine/security/trust/","label":"Docker Docs — Content trust"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Select ALL recommended Docker security hardening practices.$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Storage and Volumes$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$A container is removed with `docker rm`. What happens to data written into a named volume it used?$dca$, $dca$[{"id":"a","text":"The volume and its data are deleted along with the container."},{"id":"b","text":"The named volume and its data persist and can be reused by another container."},{"id":"c","text":"The data is moved into the image."},{"id":"d","text":"The volume becomes read-only permanently."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$Named volumes have a lifecycle independent of containers; removing the container leaves the volume and its data intact (unless `docker rm -v` or `docker volume rm` is used). Anonymous volumes can be pruned, but named ones persist.$dca$, $dca$[{"url":"https://docs.docker.com/engine/storage/volumes/","label":"Docker Docs — Volumes"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$A container is removed with `docker rm`. What happens to data written into a named volume it used?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Storage and Volumes$dca$, 2, $dca$SINGLE$dca$::"QType", $dca$Which command creates a named volume called `dbdata`?$dca$, $dca$[{"id":"a","text":"docker volume create dbdata"},{"id":"b","text":"docker volume add dbdata"},{"id":"c","text":"docker create volume dbdata"},{"id":"d","text":"docker storage new dbdata"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`docker volume create <name>` creates a managed named volume. The other forms are not valid Docker CLI commands.$dca$, $dca$[{"url":"https://docs.docker.com/engine/storage/volumes/","label":"Docker Docs — Volumes"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which command creates a named volume called `dbdata`?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 2, $dca$SINGLE$dca$::"QType", $dca$Which command makes the current manager node leave the swarm and dismantle it (last manager)?$dca$, $dca$[{"id":"a","text":"docker swarm leave --force"},{"id":"b","text":"docker swarm destroy"},{"id":"c","text":"docker node rm self"},{"id":"d","text":"docker swarm down"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`docker swarm leave --force` is required for a manager (especially the last one) to leave; without `--force` the engine refuses to avoid breaking quorum. `docker swarm destroy/down` are not valid.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/manage-nodes/","label":"Docker Docs — Manage nodes in a swarm"},{"url":"https://docs.docker.com/engine/swarm/admin_guide/","label":"Docker Docs — Administer and maintain a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which command makes the current manager node leave the swarm and dismantle it (last manager)?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$You run `docker service logs web`. What does this show?$dca$, $dca$[{"id":"a","text":"Only the logs of the manager node."},{"id":"b","text":"Aggregated logs from all tasks (replicas) of the service across the swarm."},{"id":"c","text":"The swarm Raft log."},{"id":"d","text":"Only build logs of the image."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$`docker service logs` aggregates stdout/stderr from every task of the service across nodes. It is not the Raft log or build output.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$You run `docker service logs web`. What does this show?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Which `docker service create` option reserves 512 MB of memory and limits the service to 1 CPU per task?$dca$, $dca$[{"id":"a","text":"--reserve-mem 512m --max-cpu 1"},{"id":"b","text":"--reserve-memory 512m --limit-cpu 1"},{"id":"c","text":"--memory 512m --cpus 1"},{"id":"d","text":"--mem-reservation 512m --cpu-quota 1"}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$Swarm services use `--reserve-memory`/`--reserve-cpu` for scheduling reservations and `--limit-memory`/`--limit-cpu` for hard limits. `--memory`/`--cpus` are `docker run` (standalone) flags, not service flags; the others are invalid.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which `docker service create` option reserves 512 MB of memory and limits the service to 1 CPU per task?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 4, $dca$SINGLE$dca$::"QType", $dca$A swarm has 4 manager nodes. How many manager failures can it tolerate while keeping quorum?$dca$, $dca$[{"id":"a","text":"2"},{"id":"b","text":"1"},{"id":"c","text":"3"},{"id":"d","text":"0"}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$Quorum needs a majority: with 4 managers a majority is 3, so only 1 failure is tolerated — the same as 3 managers. This is why odd numbers of managers are recommended.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/raft/","label":"Docker Docs — Raft consensus in swarm mode"},{"url":"https://docs.docker.com/engine/swarm/admin_guide/","label":"Docker Docs — Administer and maintain a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$A swarm has 4 manager nodes. How many manager failures can it tolerate while keeping quorum?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 2, $dca$SINGLE$dca$::"QType", $dca$Which command lists the running tasks (and their nodes) for the service `api`?$dca$, $dca$[{"id":"a","text":"docker service ps api"},{"id":"b","text":"docker service tasks api"},{"id":"c","text":"docker ps --service api"},{"id":"d","text":"docker node ps api"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`docker service ps api` lists the service tasks, their desired/current state, and the node each runs on. `docker node ps` lists tasks on a *node*, not a service; the other forms are invalid.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"},{"url":"https://docs.docker.com/engine/swarm/manage-nodes/","label":"Docker Docs — Manage nodes in a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which command lists the running tasks (and their nodes) for the service `api`?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 3, $dca$MULTI$dca$::"QType", $dca$Select ALL true statements about swarm node availability states.$dca$, $dca$[{"id":"a","text":"active means the node can receive new tasks."},{"id":"b","text":"pause means existing tasks keep running but no new tasks are scheduled to the node."},{"id":"c","text":"drain means existing tasks are stopped and rescheduled elsewhere and no new tasks are placed."},{"id":"d","text":"active means the node is removed from the swarm."}]$dca$::jsonb, $dca$["a","b","c"]$dca$::jsonb, $dca$active accepts new tasks; pause keeps current tasks but blocks new ones; drain evacuates and blocks scheduling. active does not remove the node from the swarm, so D is false.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/manage-nodes/","label":"Docker Docs — Manage nodes in a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Select ALL true statements about swarm node availability states.$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$A service deployed with `--mode replicated-job --replicas 5` behaves how?$dca$, $dca$[{"id":"a","text":"It keeps 5 tasks running forever."},{"id":"b","text":"It runs 5 tasks to completion (one-shot batch job) and does not restart them once they exit successfully."},{"id":"c","text":"It runs one task per node forever."},{"id":"d","text":"It is rejected — jobs are not supported in swarm."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$A replicated job runs the requested number of tasks until they complete successfully (batch semantics), unlike a long-running replicated service. Global-job is the per-node variant; jobs are supported in swarm.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$A service deployed with `--mode replicated-job --replicas 5` behaves how?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 2, $dca$TRUE_FALSE$dca$::"QType", $dca$True or False: You can run `docker service create` from a swarm worker node.$dca$, $dca$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":"Only with --force"},{"id":"d","text":"Only for global services"}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$False. Orchestration commands such as `docker service create/scale/update` must be issued against a manager node; workers only execute tasks and cannot accept these commands.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"},{"url":"https://docs.docker.com/engine/swarm/manage-nodes/","label":"Docker Docs — Manage nodes in a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$True or False: You can run `docker service create` from a swarm worker node.$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Which command rotates the swarm join tokens (e.g. after a suspected leak of a worker token)?$dca$, $dca$[{"id":"a","text":"docker swarm join-token --rotate worker"},{"id":"b","text":"docker swarm token reset worker"},{"id":"c","text":"docker node rotate-token worker"},{"id":"d","text":"docker swarm regenerate worker"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`docker swarm join-token --rotate worker` (or `manager`) invalidates the old token and issues a new one. The other commands are not valid Docker CLI syntax.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/manage-nodes/","label":"Docker Docs — Manage nodes in a swarm"},{"url":"https://docs.docker.com/engine/swarm/admin_guide/","label":"Docker Docs — Administer and maintain a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which command rotates the swarm join tokens (e.g. after a suspected leak of a worker token)?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 4, $dca$SINGLE$dca$::"QType", $dca$In a Compose/stack file, what is the effect of `deploy.placement.constraints: [node.role == manager]`?$dca$, $dca$[{"id":"a","text":"The service tasks may run on any node."},{"id":"b","text":"The service tasks are scheduled only onto manager nodes."},{"id":"c","text":"It promotes workers to managers."},{"id":"d","text":"It is ignored by docker stack deploy."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$A placement constraint of `node.role == manager` restricts the service to manager nodes (a common pattern for cluster-aware tooling). It does not change node roles and is honored by `docker stack deploy`.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/stack-deploy/","label":"Docker Docs — Deploy a stack to a swarm"},{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$In a Compose/stack file, what is the effect of `deploy.placement.constraints: [node.role == manager]`?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Which command demotes a manager node `node-2` back to a worker?$dca$, $dca$[{"id":"a","text":"docker node demote node-2"},{"id":"b","text":"docker swarm demote node-2"},{"id":"c","text":"docker node update --worker node-2"},{"id":"d","text":"docker manager rm node-2"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`docker node demote <node>` (shortcut for `docker node update --role worker`) returns a manager to worker status. The other forms are not valid.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/manage-nodes/","label":"Docker Docs — Manage nodes in a swarm"},{"url":"https://docs.docker.com/engine/swarm/admin_guide/","label":"Docker Docs — Administer and maintain a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which command demotes a manager node `node-2` back to a worker?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Image Creation, Management, and Registry$dca$, 2, $dca$SINGLE$dca$::"QType", $dca$Which Dockerfile instruction documents that the container listens on a given port at runtime (without actually publishing it)?$dca$, $dca$[{"id":"a","text":"PORT"},{"id":"b","text":"EXPOSE"},{"id":"c","text":"LISTEN"},{"id":"d","text":"PUBLISH"}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$`EXPOSE` documents the intended listening port (used by tooling and `-P`), but does not publish it to the host — you still need `-p`/`-P` at run time. `PORT`/`LISTEN`/`PUBLISH` are not Dockerfile instructions.$dca$, $dca$[{"url":"https://docs.docker.com/reference/dockerfile/","label":"Docker Docs — Dockerfile reference"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which Dockerfile instruction documents that the container listens on a given port at runtime (without actually publishing it)?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Image Creation, Management, and Registry$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$You build with `docker build --target builder -t app:dev .` on a multi-stage Dockerfile. What does `--target` do?$dca$, $dca$[{"id":"a","text":"It signs the image."},{"id":"b","text":"It stops the build at the named stage, producing an image of just that stage (useful for debugging or test images)."},{"id":"c","text":"It selects the registry to push to."},{"id":"d","text":"It sets the default CMD."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$`--target <stage>` builds only up to the named stage, so you can produce an intermediate (e.g. build/test) image without the final runtime stage. It has nothing to do with signing, registries, or CMD.$dca$, $dca$[{"url":"https://docs.docker.com/build/building/multi-stage/","label":"Docker Docs — Multi-stage builds"},{"url":"https://docs.docker.com/build/building/packaging/","label":"Docker Docs — Building images"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$You build with `docker build --target builder -t app:dev .` on a multi-stage Dockerfile. What does `--target` do?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Image Creation, Management, and Registry$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Which command lists all images present in the local Docker image store?$dca$, $dca$[{"id":"a","text":"docker images (or docker image ls)"},{"id":"b","text":"docker image list --remote"},{"id":"c","text":"docker registry ls"},{"id":"d","text":"docker ps -a --images"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`docker images` / `docker image ls` lists locally stored images with repository, tag, ID, and size. `docker ps` lists containers; the others are not valid.$dca$, $dca$[{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"},{"url":"https://docs.docker.com/build/building/best-practices/","label":"Docker Docs — Image layers and best practices"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which command lists all images present in the local Docker image store?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Image Creation, Management, and Registry$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$You want to retag an existing image `app:1.0` as `app:latest` without rebuilding. Which command?$dca$, $dca$[{"id":"a","text":"docker image tag app:1.0 app:latest"},{"id":"b","text":"docker image rename app:1.0 app:latest"},{"id":"c","text":"docker image alias app:1.0 app:latest"},{"id":"d","text":"docker tag --new app:latest app:1.0"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`docker image tag <source> <target>` adds an additional tag pointing at the same image ID (no rebuild). The other commands are not valid Docker CLI syntax.$dca$, $dca$[{"url":"https://docs.docker.com/reference/cli/docker/image/tag/","label":"Docker Docs — docker image tag"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$You want to retag an existing image `app:1.0` as `app:latest` without rebuilding. Which command?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Image Creation, Management, and Registry$dca$, 4, $dca$MULTI$dca$::"QType", $dca$Select ALL effective ways to reduce final Docker image size.$dca$, $dca$[{"id":"a","text":"Use a minimal base image (e.g. alpine or distroless)."},{"id":"b","text":"Use multi-stage builds to discard build tooling."},{"id":"c","text":"Combine related RUN steps and clean package caches in the same layer."},{"id":"d","text":"Add every debugging tool you might ever need to the runtime image."}]$dca$::jsonb, $dca$["a","b","c"]$dca$::jsonb, $dca$Minimal bases, multi-stage builds, and cleaning caches within the same RUN all shrink images. Bundling many debug tools into the runtime image does the opposite and enlarges the attack surface.$dca$, $dca$[{"url":"https://docs.docker.com/build/building/best-practices/","label":"Docker Docs — Image layers and best practices"},{"url":"https://docs.docker.com/build/building/multi-stage/","label":"Docker Docs — Multi-stage builds"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Select ALL effective ways to reduce final Docker image size.$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Image Creation, Management, and Registry$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$What is the difference between `docker save` and `docker export`?$dca$, $dca$[{"id":"a","text":"They are identical."},{"id":"b","text":"`docker save` archives one or more images with all layers and metadata; `docker export` flattens a single container's filesystem into a tar (no image history)."},{"id":"c","text":"`docker export` archives images; `docker save` archives containers."},{"id":"d","text":"Both only work on running containers."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$`docker save`/`docker load` preserve full image layer history; `docker export`/`docker import` produce a flattened single-layer filesystem from a container. They are not interchangeable and save works on images regardless of run state.$dca$, $dca$[{"url":"https://docs.docker.com/build/building/best-practices/","label":"Docker Docs — Image layers and best practices"},{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$What is the difference between `docker save` and `docker export`?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Image Creation, Management, and Registry$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Which Dockerfile instruction sets the working directory for subsequent RUN/CMD/ENTRYPOINT/COPY instructions?$dca$, $dca$[{"id":"a","text":"CD"},{"id":"b","text":"WORKDIR"},{"id":"c","text":"CHDIR"},{"id":"d","text":"PWD"}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$`WORKDIR` sets (and creates if needed) the directory used by following instructions and as the default at runtime. Using shell `cd` in a RUN does not persist across instructions; `CD`/`CHDIR`/`PWD` are not instructions.$dca$, $dca$[{"url":"https://docs.docker.com/reference/dockerfile/","label":"Docker Docs — Dockerfile reference"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which Dockerfile instruction sets the working directory for subsequent RUN/CMD/ENTRYPOINT/COPY instructions?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Image Creation, Management, and Registry$dca$, 2, $dca$TRUE_FALSE$dca$::"QType", $dca$True or False: A Dockerfile may contain multiple FROM instructions, each starting a new build stage.$dca$, $dca$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":"Only with buildx"},{"id":"d","text":"Only one FROM is ever allowed"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$True. Multiple `FROM` lines define multi-stage builds; each `FROM` begins a new stage that can be named with `AS <name>` and selectively copied from.$dca$, $dca$[{"url":"https://docs.docker.com/build/building/multi-stage/","label":"Docker Docs — Multi-stage builds"},{"url":"https://docs.docker.com/reference/dockerfile/","label":"Docker Docs — Dockerfile reference"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$True or False: A Dockerfile may contain multiple FROM instructions, each starting a new build stage.$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Image Creation, Management, and Registry$dca$, 4, $dca$SINGLE$dca$::"QType", $dca$You see a build step show `---> Using cache`. What does that mean, and how can you force a clean rebuild?$dca$, $dca$[{"id":"a","text":"It means the build failed; rerun with sudo."},{"id":"b","text":"The layer was reused from the build cache because the instruction and inputs were unchanged; use `docker build --no-cache` to rebuild everything."},{"id":"c","text":"It means the image is signed; disable content trust."},{"id":"d","text":"It means the registry served the layer; log out to fix it."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$Docker reuses a cached layer when the instruction and its inputs are unchanged; `--no-cache` disables the build cache so all steps re-execute. It is unrelated to signing or registry auth.$dca$, $dca$[{"url":"https://docs.docker.com/build/building/best-practices/","label":"Docker Docs — Image layers and best practices"},{"url":"https://docs.docker.com/build/building/packaging/","label":"Docker Docs — Building images"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$You see a build step show `---> Using cache`. What does that mean, and how can you force a clean rebuild?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Installation and Configuration$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Which daemon.json key enables IPv6 networking for containers?$dca$, $dca$[{"id":"a","text":"\"ipv6\": true"},{"id":"b","text":"\"enable-ipv6\": true"},{"id":"c","text":"\"net6\": true"},{"id":"d","text":"\"v6\": \"on\""}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$The `"ipv6": true` key (paired with a `fixed-cidr-v6` range) enables IPv6 for the default bridge in daemon.json; older docs reference `enable-ipv6` per-network, but as a daemon option the canonical key is `ipv6`. Of the listed options only the IPv6-enabling boolean is meaningful — `net6`/`v6` are not valid keys.$dca$, $dca$[{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"},{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which daemon.json key enables IPv6 networking for containers?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Installation and Configuration$dca$, 2, $dca$SINGLE$dca$::"QType", $dca$Which command shows the Docker client and daemon (server) version and API version?$dca$, $dca$[{"id":"a","text":"docker version"},{"id":"b","text":"docker info"},{"id":"c","text":"docker --release"},{"id":"d","text":"docker system version"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`docker version` prints client and server versions, the Go version, and the API version. `docker info` shows daemon configuration/stats but not the version layout; `docker --release`/`docker system version` are not valid.$dca$, $dca$[{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which command shows the Docker client and daemon (server) version and API version?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Installation and Configuration$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$You want the Docker daemon to start automatically on boot of a systemd Linux host. Which command sets that up?$dca$, $dca$[{"id":"a","text":"systemctl enable docker"},{"id":"b","text":"docker daemon --boot"},{"id":"c","text":"systemctl autostart docker"},{"id":"d","text":"docker config startup on"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`systemctl enable docker` creates the boot-time start link (add `--now` to also start it immediately). The other commands are not valid.$dca$, $dca$[{"url":"https://docs.docker.com/engine/install/","label":"Docker Docs — Install Docker Engine"},{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$You want the Docker daemon to start automatically on boot of a systemd Linux host. Which command sets that up?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Installation and Configuration$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Which command tails and follows the logs of a single container `web` started without swarm?$dca$, $dca$[{"id":"a","text":"docker logs -f web"},{"id":"b","text":"docker service logs -f web"},{"id":"c","text":"docker tail web"},{"id":"d","text":"docker container output web"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`docker logs -f web` follows the stdout/stderr captured by the container logging driver. `docker service logs` is for swarm services; `docker tail`/`docker container output` do not exist.$dca$, $dca$[{"url":"https://docs.docker.com/engine/logging/configure/","label":"Docker Docs — Configure logging drivers"},{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which command tails and follows the logs of a single container `web` started without swarm?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Installation and Configuration$dca$, 2, $dca$SINGLE$dca$::"QType", $dca$Which logging driver should you configure to ship container logs to a centralized syslog server?$dca$, $dca$[{"id":"a","text":"json-file"},{"id":"b","text":"syslog"},{"id":"c","text":"none"},{"id":"d","text":"local"}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$The `syslog` driver forwards container logs to a syslog endpoint. `json-file`/`local` store logs on the host; `none` disables collection (and `docker logs`).$dca$, $dca$[{"url":"https://docs.docker.com/engine/logging/configure/","label":"Docker Docs — Configure logging drivers"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which logging driver should you configure to ship container logs to a centralized syslog server?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Installation and Configuration$dca$, 3, $dca$MULTI$dca$::"QType", $dca$Select ALL true statements about Docker logging.$dca$, $dca$[{"id":"a","text":"With the json-file driver, docker logs can read container output."},{"id":"b","text":"With certain remote drivers (e.g. syslog/gelf), docker logs may not return output unless dual logging is enabled."},{"id":"c","text":"log-opts max-size and max-file configure json-file log rotation."},{"id":"d","text":"The none driver still allows docker logs to work normally."}]$dca$::jsonb, $dca$["a","b","c"]$dca$::jsonb, $dca$json-file (and local) support `docker logs`; some remote drivers do not unless dual logging is on; max-size/max-file rotate json-file logs. The `none` driver disables `docker logs`, so D is false.$dca$, $dca$[{"url":"https://docs.docker.com/engine/logging/configure/","label":"Docker Docs — Configure logging drivers"},{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Select ALL true statements about Docker logging.$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Networking$dca$, 2, $dca$SINGLE$dca$::"QType", $dca$Which command deletes a user-defined network named `appnet` (when no containers are attached)?$dca$, $dca$[{"id":"a","text":"docker network rm appnet"},{"id":"b","text":"docker network delete appnet"},{"id":"c","text":"docker rm network appnet"},{"id":"d","text":"docker network destroy appnet"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`docker network rm appnet` removes the network (it must have no attached containers). The other forms are not valid Docker CLI syntax.$dca$, $dca$[{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which command deletes a user-defined network named `appnet` (when no containers are attached)?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Installation and Configuration$dca$, 4, $dca$SINGLE$dca$::"QType", $dca$A daemon fails to start after editing daemon.json. The most likely cause and first thing to check is:$dca$, $dca$[{"id":"a","text":"The host has no internet."},{"id":"b","text":"Invalid JSON syntax or an unknown/duplicate key in /etc/docker/daemon.json — validate the file and check the daemon journal/logs."},{"id":"c","text":"Docker requires a reboot for every change."},{"id":"d","text":"The image cache is corrupt."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$dockerd refuses to start on malformed JSON or unrecognized options; check `journalctl -u docker` (or the daemon log) and validate `daemon.json`. Connectivity and the image cache are unrelated to a config-parse failure.$dca$, $dca$[{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"},{"url":"https://docs.docker.com/engine/install/","label":"Docker Docs — Install Docker Engine"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$A daemon fails to start after editing daemon.json. The most likely cause and first thing to check is:$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Networking$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$On a user-defined bridge network, container A wants to reach container B by a custom hostname `db`. How do you set that alias?$dca$, $dca$[{"id":"a","text":"It is impossible; only container names resolve."},{"id":"b","text":"Use --network-alias db when running container B (or networks.<net>.aliases in Compose)."},{"id":"c","text":"Edit /etc/hosts on the host."},{"id":"d","text":"Publish a port with -p db:5432."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$A network alias (`--network-alias db`) registers an extra DNS name on that user-defined network so other containers resolve `db`. Editing host `/etc/hosts` or publishing a port does not create container DNS aliases.$dca$, $dca$[{"url":"https://docs.docker.com/engine/network/drivers/bridge/","label":"Docker Docs — Bridge network driver"},{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$On a user-defined bridge network, container A wants to reach container B by a custom hostname `db`. How do you set that alias?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Networking$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$What does the `-P` (capital) flag do on `docker run`?$dca$, $dca$[{"id":"a","text":"Publishes a specific host:container port pair."},{"id":"b","text":"Publishes all ports declared with EXPOSE to random high host ports."},{"id":"c","text":"Disables port publishing."},{"id":"d","text":"Runs the container in privileged mode."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$`-P` publishes every EXPOSEd port to ephemeral host ports (see them via `docker port`). `-p` (lowercase) maps specific ports; `-P` is unrelated to privilege.$dca$, $dca$[{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"},{"url":"https://docs.docker.com/engine/network/drivers/bridge/","label":"Docker Docs — Bridge network driver"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$What does the `-P` (capital) flag do on `docker run`?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Networking$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Which daemon.json setting lets you change the default subnet pools Docker uses when creating bridge/overlay networks (e.g. to avoid clashing with corporate IP ranges)?$dca$, $dca$[{"id":"a","text":"\"default-address-pools\""},{"id":"b","text":"\"bip-range\""},{"id":"c","text":"\"subnet-pool\""},{"id":"d","text":"\"network-cidr\""}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`default-address-pools` defines the base CIDR ranges and sizes from which Docker carves new network subnets, useful to avoid overlap with existing infrastructure. The other keys are not valid.$dca$, $dca$[{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"},{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which daemon.json setting lets you change the default subnet pools Docker uses when creating bridge/overlay networks (e.g. to avoid clashing with corporate IP ranges)?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Networking$dca$, 4, $dca$MULTI$dca$::"QType", $dca$Select ALL true statements about Docker DNS and service discovery.$dca$, $dca$[{"id":"a","text":"Containers on a user-defined network resolve each other by container name via Docker's embedded DNS."},{"id":"b","text":"In swarm, a service is reachable by its service name, which resolves to a virtual IP (VIP) load-balancing across tasks by default."},{"id":"c","text":"You can switch a swarm service to DNS round-robin (dnsrr) endpoint mode instead of VIP."},{"id":"d","text":"The legacy default bridge provides automatic name-based DNS resolution."}]$dca$::jsonb, $dca$["a","b","c"]$dca$::jsonb, $dca$User-defined networks and swarm services provide embedded DNS; swarm defaults to a VIP and supports `dnsrr` mode. The legacy default bridge does NOT provide automatic name resolution, so D is false.$dca$, $dca$[{"url":"https://docs.docker.com/engine/network/drivers/bridge/","label":"Docker Docs — Bridge network driver"},{"url":"https://docs.docker.com/engine/network/drivers/overlay/","label":"Docker Docs — Overlay network driver"},{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Select ALL true statements about Docker DNS and service discovery.$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Networking$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Which command shows detailed configuration of a network, including connected containers and subnet?$dca$, $dca$[{"id":"a","text":"docker network inspect appnet"},{"id":"b","text":"docker network show appnet"},{"id":"c","text":"docker inspect --net appnet"},{"id":"d","text":"docker network detail appnet"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`docker network inspect appnet` returns the driver, subnet/gateway, options, and attached containers. The other forms are not valid Docker CLI syntax.$dca$, $dca$[{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which command shows detailed configuration of a network, including connected containers and subnet?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Networking$dca$, 4, $dca$SINGLE$dca$::"QType", $dca$A macvlan network is configured with `--subnet 192.168.10.0/24 --gateway 192.168.10.1 -o parent=eth0`. A common limitation to be aware of is:$dca$, $dca$[{"id":"a","text":"Containers cannot get IP addresses at all."},{"id":"b","text":"By default the Docker host itself cannot communicate with the macvlan containers over that interface (macvlan host/container isolation)."},{"id":"c","text":"Macvlan only works in swarm mode."},{"id":"d","text":"Macvlan disables DNS for all containers on the host."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$With macvlan, the parent host interface generally cannot talk to its own macvlan child containers without an extra macvlan sub-interface workaround. It does work outside swarm and does not globally disable DNS.$dca$, $dca$[{"url":"https://docs.docker.com/engine/network/drivers/macvlan/","label":"Docker Docs — Macvlan network driver"},{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$A macvlan network is configured with `--subnet 192.168.10.0/24 --gateway 192.168.10.1 -o parent=eth0`. A common limitation to be aware of is:$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Security$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Which `docker run` flag runs the container process as UID 1000 instead of root, overriding the image USER?$dca$, $dca$[{"id":"a","text":"--user 1000"},{"id":"b","text":"--uid 1000"},{"id":"c","text":"--as-user 1000"},{"id":"d","text":"--run-as 1000"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`--user 1000` (or `--user 1000:1000`) sets the runtime UID/GID, overriding the Dockerfile `USER`. `--uid`/`--as-user`/`--run-as` are not valid flags.$dca$, $dca$[{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"},{"url":"https://docs.docker.com/reference/cli/docker/container/run/#privileged","label":"Docker Docs — Runtime privilege and Linux capabilities"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which `docker run` flag runs the container process as UID 1000 instead of root, overriding the image USER?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Security$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$When securing the Docker daemon TCP socket, which port and protection are conventional?$dca$, $dca$[{"id":"a","text":"Port 2375 with no TLS."},{"id":"b","text":"Port 2376 protected with TLS mutual authentication (client and server certificates)."},{"id":"c","text":"Port 22 over SSH only."},{"id":"d","text":"Port 80 with basic auth."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$The convention is TLS-protected daemon access on port 2376 with mutual cert auth; port 2375 is the unencrypted (dangerous) port and should not be exposed. SSH/HTTP basic auth are not the Docker API transport.$dca$, $dca$[{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"},{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$When securing the Docker daemon TCP socket, which port and protection are conventional?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Security$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Which command updates a swarm secret's usage by removing it from a service and adding a new version (since secret contents are immutable)?$dca$, $dca$[{"id":"a","text":"docker secret edit"},{"id":"b","text":"docker service update --secret-rm old --secret-add new"},{"id":"c","text":"docker secret rotate"},{"id":"d","text":"docker secret update --value"}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$Swarm secrets are immutable, so rotation is done by creating a new secret and using `docker service update --secret-rm <old> --secret-add <new>`. There is no `docker secret edit`/`rotate`/`update --value`.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/secrets/","label":"Docker Docs — Manage sensitive data with secrets"},{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which command updates a swarm secret's usage by removing it from a service and adding a new version (since secret contents are immutable)?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Security$dca$, 2, $dca$TRUE_FALSE$dca$::"QType", $dca$True or False: Anyone with access to the Docker daemon (Unix socket or unauthenticated TCP) can effectively obtain root on the host.$dca$, $dca$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":"Only on Windows"},{"id":"d","text":"Only with --privileged"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$True. The Docker API is root-equivalent: a caller can run privileged containers and bind-mount the host filesystem, so daemon access must be tightly controlled (TLS, socket permissions).$dca$, $dca$[{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"},{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$True or False: Anyone with access to the Docker daemon (Unix socket or unauthenticated TCP) can effectively obtain root on the host.$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Security$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Which `docker run` option disables the default seccomp profile entirely (generally NOT recommended)?$dca$, $dca$[{"id":"a","text":"--security-opt seccomp=unconfined"},{"id":"b","text":"--no-seccomp"},{"id":"c","text":"--cap-drop seccomp"},{"id":"d","text":"--seccomp off"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`--security-opt seccomp=unconfined` runs the container without syscall filtering; you can also point it at a custom JSON profile. It widens the attack surface and is discouraged. The other forms are not valid.$dca$, $dca$[{"url":"https://docs.docker.com/engine/security/seccomp/","label":"Docker Docs — Seccomp security profiles"},{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which `docker run` option disables the default seccomp profile entirely (generally NOT recommended)?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Security$dca$, 4, $dca$MULTI$dca$::"QType", $dca$Select ALL controls that help limit the blast radius of a container compromise.$dca$, $dca$[{"id":"a","text":"Running the container as a non-root user."},{"id":"b","text":"Dropping unneeded Linux capabilities (--cap-drop)."},{"id":"c","text":"Enabling user-namespace remapping on the daemon."},{"id":"d","text":"Mounting the host Docker socket into the container."}]$dca$::jsonb, $dca$["a","b","c"]$dca$::jsonb, $dca$Non-root users, dropped capabilities, and userns-remap all shrink what a compromised container can do. Mounting the Docker socket does the opposite — it grants root-equivalent host control.$dca$, $dca$[{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"},{"url":"https://docs.docker.com/reference/cli/docker/container/run/#privileged","label":"Docker Docs — Runtime privilege and Linux capabilities"},{"url":"https://docs.docker.com/engine/security/userns-remap/","label":"Docker Docs — Isolate containers with a user namespace"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Select ALL controls that help limit the blast radius of a container compromise.$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Storage and Volumes$dca$, 2, $dca$SINGLE$dca$::"QType", $dca$Which command lists all Docker-managed volumes on the host?$dca$, $dca$[{"id":"a","text":"docker volume ls"},{"id":"b","text":"docker volume list --all"},{"id":"c","text":"docker ls volumes"},{"id":"d","text":"docker storage ls"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`docker volume ls` lists volumes with their driver and name. The other forms are not valid Docker CLI syntax.$dca$, $dca$[{"url":"https://docs.docker.com/engine/storage/volumes/","label":"Docker Docs — Volumes"},{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which command lists all Docker-managed volumes on the host?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Security$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Why should images be pinned by digest (image@sha256:...) in security-sensitive deployments?$dca$, $dca$[{"id":"a","text":"Digests download faster than tags."},{"id":"b","text":"A digest is immutable content-addressable, so you always run exactly the verified bytes even if a tag is later re-pushed/poisoned."},{"id":"c","text":"Digests automatically scan for CVEs."},{"id":"d","text":"Digests bypass the registry login."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$Tags are mutable and can be re-pointed; a digest guarantees the exact image content you reviewed/approved is what runs. It does not change download speed, scan for CVEs, or skip authentication.$dca$, $dca$[{"url":"https://docs.docker.com/engine/security/trust/","label":"Docker Docs — Content trust"},{"url":"https://docs.docker.com/reference/cli/docker/image/push/","label":"Docker Docs — docker push"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Why should images be pinned by digest (image@sha256:...) in security-sensitive deployments?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Storage and Volumes$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$You append `:ro` to a volume mount, e.g. `-v data:/app/data:ro`. What does this do?$dca$, $dca$[{"id":"a","text":"Deletes the volume after the container stops."},{"id":"b","text":"Mounts the volume read-only inside the container so the process cannot modify it."},{"id":"c","text":"Makes the volume reside only in RAM."},{"id":"d","text":"Replicates the volume to other hosts."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$The `:ro` option mounts the volume read-only for that container (the default is `rw`). It does not delete, move to RAM, or replicate the volume.$dca$, $dca$[{"url":"https://docs.docker.com/engine/storage/volumes/","label":"Docker Docs — Volumes"},{"url":"https://docs.docker.com/engine/storage/bind-mounts/","label":"Docker Docs — Bind mounts"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$You append `:ro` to a volume mount, e.g. `-v data:/app/data:ro`. What does this do?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Storage and Volumes$dca$, 3, $dca$TRUE_FALSE$dca$::"QType", $dca$True or False: A bind mount can shadow (hide) files that exist at the same path inside the image.$dca$, $dca$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":"Only for named volumes"},{"id":"d","text":"Only in swarm mode"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$True. A bind mount overlays the host path onto the target, hiding any image content previously at that path; unlike an empty named volume, a bind mount is never pre-populated from the image.$dca$, $dca$[{"url":"https://docs.docker.com/engine/storage/bind-mounts/","label":"Docker Docs — Bind mounts"},{"url":"https://docs.docker.com/engine/storage/volumes/","label":"Docker Docs — Volumes"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$True or False: A bind mount can shadow (hide) files that exist at the same path inside the image.$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Storage and Volumes$dca$, 4, $dca$SINGLE$dca$::"QType", $dca$A stateful database service in swarm uses a local named volume. When the task reschedules to a different node, the data is missing. What is the correct explanation/fix?$dca$, $dca$[{"id":"a","text":"Local volumes are automatically replicated; the issue must be a bug."},{"id":"b","text":"Local volumes are node-local and do not follow a rescheduled task; use a shared/clustered volume plugin (or pin the task to its node) for persistent stateful data."},{"id":"c","text":"Swarm never reschedules database tasks."},{"id":"d","text":"You must run docker volume prune to fix it."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$A `local` volume only exists on the node it was created on, so a rescheduled task on another node sees an empty/new volume. Use a volume plugin backed by shared storage, or constrain the task to its node, for durable stateful workloads.$dca$, $dca$[{"url":"https://docs.docker.com/engine/storage/volumes/","label":"Docker Docs — Volumes"},{"url":"https://docs.docker.com/engine/storage/drivers/","label":"Docker Docs — Storage drivers"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P2$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$A stateful database service in swarm uses a local named volume. When the task reschedules to a different node, the data is missing. What is the correct explanation/fix?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 2, $dca$SINGLE$dca$::"QType", $dca$Which command retrieves the worker join token needed to add a new worker node to an existing swarm?$dca$, $dca$[{"id":"a","text":"docker swarm join-token worker"},{"id":"b","text":"docker node token worker"},{"id":"c","text":"docker swarm token --worker"},{"id":"d","text":"docker swarm worker-token"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`docker swarm join-token worker` (run on a manager) prints the full `docker swarm join` command with the worker token. The other forms are not valid CLI syntax.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/manage-nodes/","label":"Docker Docs — Manage nodes in a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which command retrieves the worker join token needed to add a new worker node to an existing swarm?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$A 3-manager swarm loses 2 managers simultaneously. What is the cluster state?$dca$, $dca$[{"id":"a","text":"The swarm continues normally; 1 manager is enough."},{"id":"b","text":"The swarm loses quorum: existing tasks keep running but no new orchestration/scheduling decisions can be made until quorum is restored."},{"id":"c","text":"All running containers are immediately killed."},{"id":"d","text":"Worker nodes are automatically promoted to managers to restore quorum."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$Quorum needs a majority (2 of 3). With only 1 manager left, the control plane is read-only for orchestration — running tasks continue, but scheduling/updates are blocked until quorum is recovered. Workers are not auto-promoted.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/raft/","label":"Docker Docs — Raft consensus in swarm mode"},{"url":"https://docs.docker.com/engine/swarm/admin_guide/","label":"Docker Docs — Administer and maintain a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$A 3-manager swarm loses 2 managers simultaneously. What is the cluster state?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Which `docker service create` option restricts a service's tasks to run only on nodes labeled `region=eu`?$dca$, $dca$[{"id":"a","text":"--placement-pref region=eu"},{"id":"b","text":"--constraint node.labels.region==eu"},{"id":"c","text":"--filter region=eu"},{"id":"d","text":"--node-label region=eu"}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$`--constraint node.labels.region==eu` is a hard placement constraint. `--placement-pref` only biases spread; the other flags are not valid.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which `docker service create` option restricts a service's tasks to run only on nodes labeled `region=eu`?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$You update a swarm service image and want only one task replaced at a time, waiting 10s between batches. Which options configure this?$dca$, $dca$[{"id":"a","text":"--update-parallelism 1 --update-delay 10s"},{"id":"b","text":"--rolling 1 --pause 10s"},{"id":"c","text":"--batch-size 1 --batch-wait 10s"},{"id":"d","text":"--replicas 1 --delay 10s"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`--update-parallelism` sets how many tasks update at once and `--update-delay` the wait between batches. The other flag names are not part of the Docker service update configuration.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$You update a swarm service image and want only one task replaced at a time, waiting 10s between batches. Which options configure this?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 4, $dca$MULTI$dca$::"QType", $dca$Select ALL true statements about Docker on Kubernetes and orchestration choices.$dca$, $dca$[{"id":"a","text":"Docker Desktop can run a single-node Kubernetes cluster for local development."},{"id":"b","text":"A Docker Compose file can target either swarm (docker stack deploy) or be translated for other orchestrators."},{"id":"c","text":"Swarm mode is built into the Docker Engine and requires no separate installation."},{"id":"d","text":"Kubernetes and swarm cannot both be concepts you prepare for; only swarm exists in Docker."}]$dca$::jsonb, $dca$["a","b","c"]$dca$::jsonb, $dca$Docker Desktop bundles an optional single-node Kubernetes; Compose files drive swarm stacks; swarm mode ships in the Engine. Option D is false — both Kubernetes and swarm orchestration are relevant.$dca$, $dca$[{"url":"https://docs.docker.com/desktop/features/kubernetes/","label":"Docker Docs — Deploy on Kubernetes"},{"url":"https://docs.docker.com/engine/swarm/","label":"Docker Docs — Swarm mode overview"},{"url":"https://docs.docker.com/engine/swarm/stack-deploy/","label":"Docker Docs — Deploy a stack to a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Select ALL true statements about Docker on Kubernetes and orchestration choices.$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Image Creation, Management, and Registry$dca$, 2, $dca$SINGLE$dca$::"QType", $dca$Which command builds an image from the current directory and tags it `myapp:2.0`?$dca$, $dca$[{"id":"a","text":"docker build -t myapp:2.0 ."},{"id":"b","text":"docker image new myapp:2.0 ."},{"id":"c","text":"docker create -t myapp:2.0 ."},{"id":"d","text":"docker compile myapp:2.0 ."}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`docker build -t name:tag <context>` builds and tags an image. `docker create` makes a container from an existing image; the other commands do not exist.$dca$, $dca$[{"url":"https://docs.docker.com/build/building/packaging/","label":"Docker Docs — Building images"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which command builds an image from the current directory and tags it `myapp:2.0`?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Image Creation, Management, and Registry$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$What is the purpose of a `.dockerignore` file?$dca$, $dca$[{"id":"a","text":"It lists Dockerfile instructions to skip."},{"id":"b","text":"It excludes files/directories from the build context sent to the daemon, speeding builds and avoiding leaking secrets."},{"id":"c","text":"It marks layers as cacheable."},{"id":"d","text":"It tells the registry which tags to ignore."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$`.dockerignore` prunes the build context (e.g. .git, node_modules, secrets) before it is sent to the daemon. It has nothing to do with skipping instructions, caching, or registry tags.$dca$, $dca$[{"url":"https://docs.docker.com/build/building/packaging/","label":"Docker Docs — Building images"},{"url":"https://docs.docker.com/build/building/best-practices/","label":"Docker Docs — Image layers and best practices"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$What is the purpose of a `.dockerignore` file?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Image Creation, Management, and Registry$dca$, 3, $dca$MULTI$dca$::"QType", $dca$Select ALL true statements about Dockerfile best practices.$dca$, $dca$[{"id":"a","text":"Order instructions so that frequently changing layers (e.g. app source) come after stable ones (e.g. dependency install) to maximize cache reuse."},{"id":"b","text":"Prefer a minimal base image to reduce size and attack surface."},{"id":"c","text":"Use multi-stage builds to keep build-only tooling out of the final image."},{"id":"d","text":"Always run the application as root for compatibility."}]$dca$::jsonb, $dca$["a","b","c"]$dca$::jsonb, $dca$Layer ordering for cache, minimal bases, and multi-stage builds are recommended. Running as root is discouraged — prefer a dedicated non-root USER.$dca$, $dca$[{"url":"https://docs.docker.com/build/building/best-practices/","label":"Docker Docs — Image layers and best practices"},{"url":"https://docs.docker.com/build/building/multi-stage/","label":"Docker Docs — Multi-stage builds"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Select ALL true statements about Dockerfile best practices.$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Image Creation, Management, and Registry$dca$, 4, $dca$SINGLE$dca$::"QType", $dca$Difference between `ENTRYPOINT ["app"]` and `CMD ["app"]` when the user runs `docker run image arg1`?$dca$, $dca$[{"id":"a","text":"Both are completely replaced by arg1."},{"id":"b","text":"With ENTRYPOINT, arg1 is appended as an argument to app; with CMD, arg1 replaces the command entirely."},{"id":"c","text":"CMD runs at build time; ENTRYPOINT at run time."},{"id":"d","text":"There is no functional difference."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$Run-time arguments are appended to an exec-form ENTRYPOINT but override CMD. A common pattern is ENTRYPOINT for the binary and CMD for default args. Neither runs at build time (that is RUN).$dca$, $dca$[{"url":"https://docs.docker.com/reference/dockerfile/","label":"Docker Docs — Dockerfile reference"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Difference between `ENTRYPOINT ["app"]` and `CMD ["app"]` when the user runs `docker run image arg1`?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Installation and Configuration$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Which daemon.json key configures the daemon to listen on a TCP socket in addition to the default Unix socket?$dca$, $dca$[{"id":"a","text":"\"hosts\": [\"unix:///var/run/docker.sock\", \"tcp://0.0.0.0:2376\"]"},{"id":"b","text":"\"listen\": \"tcp://0.0.0.0:2376\""},{"id":"c","text":"\"bind\": \"0.0.0.0:2376\""},{"id":"d","text":"\"api-port\": 2376"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$The `hosts` array sets the sockets dockerd listens on. Exposing TCP should be paired with TLS (port 2376). The other keys are not valid daemon options.$dca$, $dca$[{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"},{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which daemon.json key configures the daemon to listen on a TCP socket in addition to the default Unix socket?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Installation and Configuration$dca$, 2, $dca$SINGLE$dca$::"QType", $dca$Which command would you use to reclaim disk by removing stopped containers, unused networks, dangling images, and build cache?$dca$, $dca$[{"id":"a","text":"docker system prune"},{"id":"b","text":"docker clean --all"},{"id":"c","text":"docker gc"},{"id":"d","text":"docker rmi --unused"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`docker system prune` removes stopped containers, unused networks, dangling images, and build cache (add `-a`/`--volumes` for more). The other commands are not valid.$dca$, $dca$[{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which command would you use to reclaim disk by removing stopped containers, unused networks, dangling images, and build cache?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Installation and Configuration$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$You set `"live-restore": true` in daemon.json. What does this enable?$dca$, $dca$[{"id":"a","text":"Containers keep running while the Docker daemon is down (e.g. during a daemon upgrade/restart)."},{"id":"b","text":"Automatic restart of the daemon if it crashes."},{"id":"c","text":"Live migration of containers between hosts."},{"id":"d","text":"Real-time replication of volumes."}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$live-restore keeps containers running during daemon downtime/upgrades. It is not crash auto-restart, container live migration, or volume replication.$dca$, $dca$[{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$You set `"live-restore": true` in daemon.json. What does this enable?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Networking$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$You run `docker run -d -p 127.0.0.1:8080:80 nginx`. Who can reach the web server?$dca$, $dca$[{"id":"a","text":"Anyone on the network via the host's external IP on port 8080."},{"id":"b","text":"Only clients on the host itself (loopback), since the publish is bound to 127.0.0.1."},{"id":"c","text":"Only other containers on the bridge network."},{"id":"d","text":"No one — binding to 127.0.0.1 disables the port."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$Specifying `127.0.0.1:8080:80` binds the published port to the host loopback only, so remote hosts cannot reach it — useful for restricting exposure. Containers on the bridge reach nginx by its container IP regardless.$dca$, $dca$[{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"},{"url":"https://docs.docker.com/engine/network/drivers/bridge/","label":"Docker Docs — Bridge network driver"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$You run `docker run -d -p 127.0.0.1:8080:80 nginx`. Who can reach the web server?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Networking$dca$, 2, $dca$TRUE_FALSE$dca$::"QType", $dca$True or False: Containers attached to the default (legacy) bridge network get automatic DNS-based name resolution between each other just like on user-defined bridge networks.$dca$, $dca$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":"Only with --link"},{"id":"d","text":"Only in swarm mode"}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$False. The default `bridge` network does NOT provide automatic container name resolution; only user-defined networks include the embedded DNS server. The legacy `--link` flag was the old workaround on the default bridge.$dca$, $dca$[{"url":"https://docs.docker.com/engine/network/drivers/bridge/","label":"Docker Docs — Bridge network driver"},{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$True or False: Containers attached to the default (legacy) bridge network get automatic DNS-based name resolution between each other just like on user-defined bridge networks.$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Networking$dca$, 4, $dca$SINGLE$dca$::"QType", $dca$In swarm mode, what is the `ingress` network used for?$dca$, $dca$[{"id":"a","text":"It is a user-defined overlay you must create before deploying any service."},{"id":"b","text":"It is a special built-in overlay network that carries the routing-mesh traffic for services that publish ports."},{"id":"c","text":"It connects manager nodes' Raft traffic."},{"id":"d","text":"It is the default bridge each swarm node uses for local containers."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$The `ingress` overlay is created automatically with the swarm and handles routing-mesh load-balanced traffic for published service ports. Raft control traffic and the local default bridge are separate.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/ingress/","label":"Docker Docs — Use swarm mode routing mesh"},{"url":"https://docs.docker.com/engine/network/drivers/overlay/","label":"Docker Docs — Overlay network driver"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$In swarm mode, what is the `ingress` network used for?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Security$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Why is exposing the Docker daemon on an unauthenticated TCP socket (e.g. tcp://0.0.0.0:2375) dangerous?$dca$, $dca$[{"id":"a","text":"It only slows down image pulls."},{"id":"b","text":"Anyone who can reach the socket can run containers and effectively gain root on the host."},{"id":"c","text":"It disables container logging."},{"id":"d","text":"It prevents the use of volumes."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$The Docker API is root-equivalent: full access to the daemon allows running privileged containers and mounting the host filesystem. Always require TLS/mutual auth (port 2376) or keep it on the Unix socket.$dca$, $dca$[{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"},{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Why is exposing the Docker daemon on an unauthenticated TCP socket (e.g. tcp://0.0.0.0:2375) dangerous?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Security$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Which Dockerfile instruction helps reduce risk by ensuring the container process does not run as root?$dca$, $dca$[{"id":"a","text":"PRIVILEGE none"},{"id":"b","text":"USER appuser"},{"id":"c","text":"ROOT off"},{"id":"d","text":"SECURITY nonroot"}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$The `USER` instruction sets the UID/username the container runs as, enabling least-privilege non-root execution. The other instructions do not exist.$dca$, $dca$[{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"},{"url":"https://docs.docker.com/reference/dockerfile/","label":"Docker Docs — Dockerfile reference"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which Dockerfile instruction helps reduce risk by ensuring the container process does not run as root?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Security$dca$, 4, $dca$SINGLE$dca$::"QType", $dca$Image vulnerability scanning (e.g. docker scout) primarily helps you to:$dca$, $dca$[{"id":"a","text":"Sign images so only trusted ones run."},{"id":"b","text":"Identify known CVEs in the packages and base layers of an image so you can remediate them."},{"id":"c","text":"Restrict syscalls available to the container."},{"id":"d","text":"Remap container UIDs to the host."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$Scanning surfaces known vulnerabilities (CVEs) in image contents so you can patch/upgrade. Signing is content trust, syscall restriction is seccomp, and UID remap is userns — different controls.$dca$, $dca$[{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"},{"url":"https://docs.docker.com/engine/security/trust/","label":"Docker Docs — Content trust"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Image vulnerability scanning (e.g. docker scout) primarily helps you to:$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Storage and Volumes$dca$, 2, $dca$SINGLE$dca$::"QType", $dca$Which docker run syntax mounts the named volume `data` at `/var/lib/app` inside the container?$dca$, $dca$[{"id":"a","text":"docker run -v data:/var/lib/app myimg"},{"id":"b","text":"docker run --mount /var/lib/app=data myimg"},{"id":"c","text":"docker run --volume=/data myimg"},{"id":"d","text":"docker run -p data:/var/lib/app myimg"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`-v <volumename>:<container-path>` mounts a named volume (equivalently `--mount type=volume,source=data,target=/var/lib/app`). `-p` publishes ports, not volumes; the other forms are malformed.$dca$, $dca$[{"url":"https://docs.docker.com/engine/storage/volumes/","label":"Docker Docs — Volumes"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which docker run syntax mounts the named volume `data` at `/var/lib/app` inside the container?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Storage and Volumes$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$A copy-on-write storage driver like overlay2 affects container write performance how?$dca$, $dca$[{"id":"a","text":"All writes are blocked unless a volume is attached."},{"id":"b","text":"The first modification of a file from a lower image layer triggers a copy-up into the container layer, adding overhead for write-heavy workloads."},{"id":"c","text":"Writes are faster than a bind mount in every case."},{"id":"d","text":"It stores writes directly back into the image layers."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$Copy-on-write copies a file up from the image layers to the writable layer on first modification, which is costly for write-heavy or large-file workloads — hence using volumes/bind mounts for such data. Image layers themselves remain read-only.$dca$, $dca$[{"url":"https://docs.docker.com/engine/storage/drivers/","label":"Docker Docs — Storage drivers"},{"url":"https://docs.docker.com/engine/storage/volumes/","label":"Docker Docs — Volumes"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$A copy-on-write storage driver like overlay2 affects container write performance how?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 2, $dca$SINGLE$dca$::"QType", $dca$Which command retrieves the manager join token for adding another manager to an existing swarm?$dca$, $dca$[{"id":"a","text":"docker swarm join-token manager"},{"id":"b","text":"docker node token manager"},{"id":"c","text":"docker swarm manager-token"},{"id":"d","text":"docker swarm token --manager"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`docker swarm join-token manager` (run on a manager) prints the full join command with the manager token. The other forms are not valid Docker CLI syntax.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/manage-nodes/","label":"Docker Docs — Manage nodes in a swarm"},{"url":"https://docs.docker.com/engine/swarm/admin_guide/","label":"Docker Docs — Administer and maintain a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which command retrieves the manager join token for adding another manager to an existing swarm?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$What does `docker service inspect --pretty web` provide?$dca$, $dca$[{"id":"a","text":"Only the container logs."},{"id":"b","text":"A human-readable summary of the service spec: image, mode, replicas, networks, update config, etc."},{"id":"c","text":"The Raft store contents."},{"id":"d","text":"The Dockerfile used to build the image."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$`docker service inspect --pretty` formats the service definition (image, replicas/mode, ports, update policy) for humans; without `--pretty` it returns JSON. It does not expose logs, the Raft store, or the Dockerfile.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$What does `docker service inspect --pretty web` provide?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Which option on `docker service update` adds a published port to an existing service?$dca$, $dca$[{"id":"a","text":"--port-add 8080:80"},{"id":"b","text":"--publish-add 8080:80"},{"id":"c","text":"--expose-add 8080:80"},{"id":"d","text":"--add-port 8080:80"}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$Service updates use `--publish-add`/`--publish-rm` to change published ports (mirrored by `--env-add`, `--mount-add`, etc.). `--port-add`/`--expose-add`/`--add-port` are not valid options.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"},{"url":"https://docs.docker.com/engine/swarm/ingress/","label":"Docker Docs — Use swarm mode routing mesh"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which option on `docker service update` adds a published port to an existing service?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 4, $dca$SINGLE$dca$::"QType", $dca$You want at most one replica of a service per node (spread it out) without forcing global mode. Which placement option helps?$dca$, $dca$[{"id":"a","text":"--replicas-max-per-node 1"},{"id":"b","text":"--placement-pref spread=node.id"},{"id":"c","text":"--constraint node.role==worker"},{"id":"d","text":"--mode global only"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`--replicas-max-per-node 1` caps how many tasks of the service may run on a single node, spreading replicas without using global mode. `--placement-pref spread` biases distribution but does not hard-cap per node; a role constraint just filters nodes.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$You want at most one replica of a service per node (spread it out) without forcing global mode. Which placement option helps?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 2, $dca$SINGLE$dca$::"QType", $dca$Which command lists the stacks currently deployed to the swarm?$dca$, $dca$[{"id":"a","text":"docker stack ls"},{"id":"b","text":"docker stack list --all"},{"id":"c","text":"docker swarm stacks"},{"id":"d","text":"docker service stacks"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`docker stack ls` lists deployed stacks and their service counts. The other forms are not valid Docker CLI syntax.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/stack-deploy/","label":"Docker Docs — Deploy a stack to a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which command lists the stacks currently deployed to the swarm?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 3, $dca$MULTI$dca$::"QType", $dca$Select ALL true statements about swarm certificates and security.$dca$, $dca$[{"id":"a","text":"Swarm uses mutual TLS between nodes for control-plane communication."},{"id":"b","text":"Manager and worker join tokens differ and can be rotated independently."},{"id":"c","text":"The CA certificate expiry/rotation interval can be configured with docker swarm update --cert-expiry."},{"id":"d","text":"Swarm sends all node traffic in plaintext by default."}]$dca$::jsonb, $dca$["a","b","c"]$dca$::jsonb, $dca$Swarm auto-provisions a CA and uses mutual TLS; tokens are role-specific and rotatable; `--cert-expiry` tunes certificate rotation. Control-plane traffic is encrypted by default, so D is false.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/admin_guide/","label":"Docker Docs — Administer and maintain a swarm"},{"url":"https://docs.docker.com/engine/swarm/","label":"Docker Docs — Swarm mode overview"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Select ALL true statements about swarm certificates and security.$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$A swarm service uses `--restart-condition on-failure`. What does this mean for its tasks?$dca$, $dca$[{"id":"a","text":"Tasks are restarted only when they exit with a non-zero status."},{"id":"b","text":"Tasks never restart."},{"id":"c","text":"Tasks restart even on a clean (zero) exit."},{"id":"d","text":"Tasks restart only when the node reboots."}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`on-failure` restarts a task only on non-zero exit; `any` (the default) restarts regardless of exit code, and `none` never restarts. It is independent of node reboots.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$A swarm service uses `--restart-condition on-failure`. What does this mean for its tasks?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 2, $dca$TRUE_FALSE$dca$::"QType", $dca$True or False: In a swarm, manager nodes can also run service tasks (act as workers) by default.$dca$, $dca$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":"Only if drained"},{"id":"d","text":"Only single-node swarms"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$True. By default managers also schedule and run tasks; you can set a manager to `Drain` availability if you want it to handle orchestration only and not run workloads.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/manage-nodes/","label":"Docker Docs — Manage nodes in a swarm"},{"url":"https://docs.docker.com/engine/swarm/admin_guide/","label":"Docker Docs — Administer and maintain a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$True or False: In a swarm, manager nodes can also run service tasks (act as workers) by default.$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$How do swarm configs differ from swarm secrets?$dca$, $dca$[{"id":"a","text":"Configs are encrypted at rest in Raft and mounted at /run/secrets; secrets are plaintext."},{"id":"b","text":"Configs are for non-sensitive data and are not encrypted at rest the way secrets are; secrets are encrypted in the Raft log and intended for sensitive values."},{"id":"c","text":"They are identical features with different names."},{"id":"d","text":"Configs can only hold binary data; secrets only text."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$Secrets are encrypted in the Raft store and mounted at `/run/secrets` for sensitive data; configs deliver non-sensitive configuration files and are not given the same at-rest encryption guarantees. Both can hold text or binary.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/configs/","label":"Docker Docs — Store configuration data using configs"},{"url":"https://docs.docker.com/engine/swarm/secrets/","label":"Docker Docs — Manage sensitive data with secrets"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$How do swarm configs differ from swarm secrets?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 4, $dca$SINGLE$dca$::"QType", $dca$After losing quorum (most managers gone) and being unable to recover them, which command can force a single surviving manager to form a new single-manager cluster from the existing Raft state?$dca$, $dca$[{"id":"a","text":"docker swarm init --force-new-cluster"},{"id":"b","text":"docker swarm recover"},{"id":"c","text":"docker node promote --force"},{"id":"d","text":"docker swarm join --rebuild"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`docker swarm init --force-new-cluster` (run on a surviving manager) reinitializes the swarm from the local Raft data with a single manager, after which you re-add managers/workers. The other commands are not valid recovery operations.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/admin_guide/","label":"Docker Docs — Administer and maintain a swarm"},{"url":"https://docs.docker.com/engine/swarm/raft/","label":"Docker Docs — Raft consensus in swarm mode"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$After losing quorum (most managers gone) and being unable to recover them, which command can force a single surviving manager to form a new single-manager cluster from the existing Raft state?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Orchestration$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Which command removes the swarm service `web` and stops all of its tasks?$dca$, $dca$[{"id":"a","text":"docker service rm web"},{"id":"b","text":"docker service stop web"},{"id":"c","text":"docker service delete web"},{"id":"d","text":"docker swarm rm web"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`docker service rm web` removes the service and terminates its tasks (there is no `docker service stop`/`delete`). `docker swarm rm` is not a valid subcommand.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which command removes the swarm service `web` and stops all of its tasks?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Image Creation, Management, and Registry$dca$, 2, $dca$SINGLE$dca$::"QType", $dca$Which Dockerfile instruction adds key/value metadata (e.g. maintainer, version) to the image?$dca$, $dca$[{"id":"a","text":"META"},{"id":"b","text":"LABEL"},{"id":"c","text":"TAG"},{"id":"d","text":"ANNOTATE"}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$`LABEL key=value` attaches metadata visible via `docker inspect`/`docker image inspect`. `MAINTAINER` is deprecated in favor of LABEL; `META`/`TAG`/`ANNOTATE` are not Dockerfile instructions.$dca$, $dca$[{"url":"https://docs.docker.com/reference/dockerfile/","label":"Docker Docs — Dockerfile reference"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which Dockerfile instruction adds key/value metadata (e.g. maintainer, version) to the image?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Image Creation, Management, and Registry$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$You want a build to fail if a required build argument is not provided. Which Dockerfile pattern enforces this?$dca$, $dca$[{"id":"a","text":"Declare ARG REQUIRED and reference ${REQUIRED:?error message} in a RUN step."},{"id":"b","text":"Use CMD to validate it."},{"id":"c","text":"Add VALIDATE ARG to the Dockerfile."},{"id":"d","text":"It is impossible; args are always optional."}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$Declaring the `ARG` and using a shell parameter expansion like `${REQUIRED:?msg}` in a RUN causes the build to error if it is empty/unset. CMD runs at container start, not build; `VALIDATE ARG` is not an instruction.$dca$, $dca$[{"url":"https://docs.docker.com/reference/dockerfile/","label":"Docker Docs — Dockerfile reference"},{"url":"https://docs.docker.com/build/building/packaging/","label":"Docker Docs — Building images"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$You want a build to fail if a required build argument is not provided. Which Dockerfile pattern enforces this?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Image Creation, Management, and Registry$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Which command removes the local image `myapp:1.0`?$dca$, $dca$[{"id":"a","text":"docker rmi myapp:1.0 (or docker image rm myapp:1.0)"},{"id":"b","text":"docker image delete myapp:1.0"},{"id":"c","text":"docker rm -i myapp:1.0"},{"id":"d","text":"docker prune myapp:1.0"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`docker rmi` / `docker image rm` deletes an image (use `-f` if it is tagged multiple times or in use). `docker rm` removes containers; the other forms are not valid.$dca$, $dca$[{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"},{"url":"https://docs.docker.com/build/building/best-practices/","label":"Docker Docs — Image layers and best practices"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which command removes the local image `myapp:1.0`?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Image Creation, Management, and Registry$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$In `COPY --from=builder /app/bin /usr/local/bin/`, what does `--from=builder` reference?$dca$, $dca$[{"id":"a","text":"A remote registry named builder."},{"id":"b","text":"A previous build stage named builder, so artifacts are copied from that stage into the current one."},{"id":"c","text":"A volume called builder."},{"id":"d","text":"The host filesystem path /builder."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$`--from=<stage>` (or `--from=<image>`) copies files from an earlier multi-stage build stage (here `builder`) into the current stage — the core mechanism of multi-stage builds. It is not a registry, volume, or host path.$dca$, $dca$[{"url":"https://docs.docker.com/build/building/multi-stage/","label":"Docker Docs — Multi-stage builds"},{"url":"https://docs.docker.com/reference/dockerfile/","label":"Docker Docs — Dockerfile reference"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$In `COPY --from=builder /app/bin /usr/local/bin/`, what does `--from=builder` reference?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Image Creation, Management, and Registry$dca$, 4, $dca$MULTI$dca$::"QType", $dca$Select ALL true statements about image tags and the `latest` tag.$dca$, $dca$[{"id":"a","text":"latest is just a conventional default tag, not automatically the newest build."},{"id":"b","text":"Pulling an image without a tag defaults to the latest tag."},{"id":"c","text":"A tag can be re-pointed to a different image by tagging/pushing again."},{"id":"d","text":"latest always guarantees the most recently built version of an image."}]$dca$::jsonb, $dca$["a","b","c"]$dca$::jsonb, $dca$`latest` is only the default tag name with no recency guarantee; an untagged pull uses `:latest`; tags are mutable pointers. Therefore D is false — `latest` does not guarantee the newest build.$dca$, $dca$[{"url":"https://docs.docker.com/reference/cli/docker/image/tag/","label":"Docker Docs — docker image tag"},{"url":"https://docs.docker.com/reference/cli/docker/image/push/","label":"Docker Docs — docker push"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Select ALL true statements about image tags and the `latest` tag.$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Image Creation, Management, and Registry$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$A private registry returns "no basic auth credentials" on push. What is the most likely fix?$dca$, $dca$[{"id":"a","text":"Rebuild the image with --no-cache."},{"id":"b","text":"Run docker login <registry> to authenticate before pushing."},{"id":"c","text":"Add the image to .dockerignore."},{"id":"d","text":"Enable Docker Content Trust."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$That error means the CLI has no stored credentials for the registry; `docker login <registry>` authenticates and stores them so the push is authorized. Rebuilding, .dockerignore, and content trust are unrelated to the auth failure.$dca$, $dca$[{"url":"https://docs.docker.com/registry/","label":"Docker Docs — Docker registry"},{"url":"https://docs.docker.com/reference/cli/docker/image/push/","label":"Docker Docs — docker push"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$A private registry returns "no basic auth credentials" on push. What is the most likely fix?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Image Creation, Management, and Registry$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Why is the order of Dockerfile instructions important for build speed?$dca$, $dca$[{"id":"a","text":"Docker runs later instructions first."},{"id":"b","text":"A change to an instruction invalidates the cache for it and all subsequent layers, so put rarely changing steps (e.g. dependency install) before frequently changing ones (e.g. COPY source)."},{"id":"c","text":"Order has no effect on caching."},{"id":"d","text":"Only the FROM line affects caching."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$The build cache is sequential: once a layer changes, every following layer is rebuilt. Placing stable steps early (and volatile COPY of source late) maximizes cache hits and speeds rebuilds.$dca$, $dca$[{"url":"https://docs.docker.com/build/building/best-practices/","label":"Docker Docs — Image layers and best practices"},{"url":"https://docs.docker.com/build/building/packaging/","label":"Docker Docs — Building images"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Why is the order of Dockerfile instructions important for build speed?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Image Creation, Management, and Registry$dca$, 2, $dca$TRUE_FALSE$dca$::"QType", $dca$True or False: `docker commit` creates a new image from the current state of a running or stopped container.$dca$, $dca$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":"Only for paused containers"},{"id":"d","text":"Only in swarm mode"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$True. `docker commit <container> <image>` snapshots a container's filesystem into a new image, though building from a Dockerfile is preferred for reproducibility.$dca$, $dca$[{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"},{"url":"https://docs.docker.com/build/building/best-practices/","label":"Docker Docs — Image layers and best practices"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$True or False: `docker commit` creates a new image from the current state of a running or stopped container.$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Image Creation, Management, and Registry$dca$, 4, $dca$SINGLE$dca$::"QType", $dca$You want to keep the build cache reusable across CI runners that do not share local storage. Which BuildKit feature helps?$dca$, $dca$[{"id":"a","text":"Registry-backed build cache via --cache-to/--cache-from with buildx."},{"id":"b","text":"The .dockerignore file."},{"id":"c","text":"Docker Content Trust."},{"id":"d","text":"The HEALTHCHECK instruction."}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$BuildKit/buildx can export and import the build cache to/from a registry (`--cache-to`, `--cache-from`), letting ephemeral CI runners share cache. .dockerignore, content trust, and HEALTHCHECK do not address cache portability.$dca$, $dca$[{"url":"https://docs.docker.com/build/building/packaging/","label":"Docker Docs — Building images"},{"url":"https://docs.docker.com/build/building/multi-stage/","label":"Docker Docs — Multi-stage builds"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$You want to keep the build cache reusable across CI runners that do not share local storage. Which BuildKit feature helps?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Installation and Configuration$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Which daemon.json key configures a list of DNS servers given to containers by default?$dca$, $dca$[{"id":"a","text":"\"dns\": [\"8.8.8.8\", \"1.1.1.1\"]"},{"id":"b","text":"\"resolvers\": [\"8.8.8.8\"]"},{"id":"c","text":"\"nameservers\": [\"8.8.8.8\"]"},{"id":"d","text":"\"dns-config\": \"8.8.8.8\""}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$The `dns` array sets the default DNS servers placed in containers' resolv.conf (overridable per-container with `--dns`). The other keys are not valid daemon options.$dca$, $dca$[{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"},{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which daemon.json key configures a list of DNS servers given to containers by default?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Installation and Configuration$dca$, 2, $dca$SINGLE$dca$::"QType", $dca$Which command removes ALL stopped containers in one step?$dca$, $dca$[{"id":"a","text":"docker container prune"},{"id":"b","text":"docker rm --all-stopped"},{"id":"c","text":"docker clean containers"},{"id":"d","text":"docker container gc"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`docker container prune` deletes all stopped containers (with a confirmation prompt unless `-f`). The other commands are not valid Docker CLI syntax.$dca$, $dca$[{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which command removes ALL stopped containers in one step?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Installation and Configuration$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$You want to limit a single container to 512 MB of memory and 50% of one CPU. Which docker run flags apply?$dca$, $dca$[{"id":"a","text":"--memory 512m --cpus 0.5"},{"id":"b","text":"--mem 512 --cpu 50"},{"id":"c","text":"--ram 512m --cpu-limit 0.5"},{"id":"d","text":"--limit-mem 512m --limit-cpu 0.5"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`--memory 512m` sets the hard memory limit and `--cpus 0.5` caps CPU to half a core for a standalone container. The other flag names are not valid Docker run options.$dca$, $dca$[{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"},{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$You want to limit a single container to 512 MB of memory and 50% of one CPU. Which docker run flags apply?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Installation and Configuration$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Which command opens an interactive shell inside an already-running container `web`?$dca$, $dca$[{"id":"a","text":"docker exec -it web /bin/sh"},{"id":"b","text":"docker run -it web /bin/sh"},{"id":"c","text":"docker attach web sh"},{"id":"d","text":"docker shell web"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`docker exec -it web /bin/sh` starts a new interactive process in the running container. `docker run` would start a *new* container; `docker attach` connects to the main process stdio, not a new shell; `docker shell` is not a command.$dca$, $dca$[{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which command opens an interactive shell inside an already-running container `web`?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Installation and Configuration$dca$, 2, $dca$SINGLE$dca$::"QType", $dca$Which command shows the low-level JSON configuration and state of a container `web`?$dca$, $dca$[{"id":"a","text":"docker inspect web"},{"id":"b","text":"docker container info web"},{"id":"c","text":"docker show web"},{"id":"d","text":"docker describe web"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`docker inspect web` returns detailed JSON (config, mounts, networks, state). The other commands are not valid Docker CLI syntax.$dca$, $dca$[{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which command shows the low-level JSON configuration and state of a container `web`?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Installation and Configuration$dca$, 3, $dca$MULTI$dca$::"QType", $dca$Select ALL true statements about Docker installation and the daemon on Linux.$dca$, $dca$[{"id":"a","text":"dockerd is the daemon and the docker CLI is a separate client that talks to it over a socket."},{"id":"b","text":"On systemd hosts the service is typically managed via systemctl (start/stop/enable docker)."},{"id":"c","text":"daemon.json changes generally require a daemon restart (or reload) to take effect."},{"id":"d","text":"The docker CLI must run on the same host as dockerd and cannot be remote."}]$dca$::jsonb, $dca$["a","b","c"]$dca$::jsonb, $dca$The CLI is a client to `dockerd` over a socket, managed by systemd, and config changes need a restart/reload. The CLI can target a remote daemon (e.g. via TLS TCP or contexts), so D is false.$dca$, $dca$[{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"},{"url":"https://docs.docker.com/engine/install/","label":"Docker Docs — Install Docker Engine"},{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Select ALL true statements about Docker installation and the daemon on Linux.$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Installation and Configuration$dca$, 4, $dca$SINGLE$dca$::"QType", $dca$You want to switch the docker CLI between multiple daemons (local, remote TLS) without changing env vars each time. Which feature is intended for this?$dca$, $dca$[{"id":"a","text":"docker context (docker context create/use)"},{"id":"b","text":"docker profile"},{"id":"c","text":"daemon.json aliases"},{"id":"d","text":"docker daemon switch"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$Docker contexts store endpoint/TLS settings per environment so `docker context use <name>` switches the active daemon target. `docker profile`/`docker daemon switch` and daemon.json aliases do not exist.$dca$, $dca$[{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"},{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$You want to switch the docker CLI between multiple daemons (local, remote TLS) without changing env vars each time. Which feature is intended for this?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Networking$dca$, 2, $dca$SINGLE$dca$::"QType", $dca$Which command shows the public-facing host port mappings of a running container `web`?$dca$, $dca$[{"id":"a","text":"docker port web"},{"id":"b","text":"docker network port web"},{"id":"c","text":"docker inspect --ports web"},{"id":"d","text":"docker ps --ports web"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`docker port web` lists the container-to-host port mappings. `docker ps` shows ports in a column but `docker port` is the dedicated command; the other forms are not valid.$dca$, $dca$[{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"},{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which command shows the public-facing host port mappings of a running container `web`?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Networking$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Why is the default `bridge` network generally discouraged for multi-container apps in favor of a user-defined bridge?$dca$, $dca$[{"id":"a","text":"The default bridge is slower hardware."},{"id":"b","text":"User-defined bridges add automatic DNS-based service discovery and better isolation; the default bridge requires legacy --link and shares all containers."},{"id":"c","text":"The default bridge cannot reach the internet."},{"id":"d","text":"User-defined bridges are required for single containers."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$User-defined bridges provide embedded DNS (resolve by container name) and segment containers; the legacy default bridge lacks automatic name resolution and groups every container together. Both have internet access via NAT.$dca$, $dca$[{"url":"https://docs.docker.com/engine/network/drivers/bridge/","label":"Docker Docs — Bridge network driver"},{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Why is the default `bridge` network generally discouraged for multi-container apps in favor of a user-defined bridge?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Networking$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Which `docker run` option disconnects a container from networking entirely?$dca$, $dca$[{"id":"a","text":"--network none"},{"id":"b","text":"--no-net"},{"id":"c","text":"--network disabled"},{"id":"d","text":"--isolate-net"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`--network none` attaches the container to the `none` network so it has only loopback. `--no-net`/`--network disabled`/`--isolate-net` are not valid options.$dca$, $dca$[{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which `docker run` option disconnects a container from networking entirely?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Networking$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$You created an overlay network but a standalone (non-service) container cannot attach to it. What likely needs to change?$dca$, $dca$[{"id":"a","text":"Overlay networks never allow containers."},{"id":"b","text":"Recreate the overlay network with the --attachable flag so standalone containers may join it."},{"id":"c","text":"Switch the container to host networking."},{"id":"d","text":"Disable the routing mesh."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$By default swarm overlay networks only accept service tasks; creating them with `--attachable` lets standalone containers connect too. Host networking and disabling the mesh do not address attachability.$dca$, $dca$[{"url":"https://docs.docker.com/engine/network/drivers/overlay/","label":"Docker Docs — Overlay network driver"},{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$You created an overlay network but a standalone (non-service) container cannot attach to it. What likely needs to change?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Networking$dca$, 4, $dca$MULTI$dca$::"QType", $dca$Select ALL true statements about publishing ports.$dca$, $dca$[{"id":"a","text":"-p 8080:80 maps host 8080 to container 80 on all host interfaces by default."},{"id":"b","text":"-p 127.0.0.1:8080:80 restricts the published port to the host loopback only."},{"id":"c","text":"-p 80 (single value) lets Docker pick a random host port for container port 80."},{"id":"d","text":"EXPOSE in a Dockerfile publishes the port to the host automatically."}]$dca$::jsonb, $dca$["a","b","c"]$dca$::jsonb, $dca$Port publishing supports all-interface, loopback-bound, and ephemeral host-port forms. `EXPOSE` only documents the port — it does not publish it; you still need `-p`/`-P`, so D is false.$dca$, $dca$[{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"},{"url":"https://docs.docker.com/engine/network/drivers/bridge/","label":"Docker Docs — Bridge network driver"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Select ALL true statements about publishing ports.$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Networking$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$In swarm, a service's default endpoint mode is `vip`. What does that mean for clients resolving the service name?$dca$, $dca$[{"id":"a","text":"Each task IP is returned directly in round-robin."},{"id":"b","text":"The service name resolves to a single stable virtual IP; the swarm load-balances connections across healthy tasks behind it."},{"id":"c","text":"Clients must use the node IPs directly."},{"id":"d","text":"The service is unreachable until you set dnsrr."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$In `vip` mode the service name resolves to one virtual IP and swarm internally load-balances to tasks. `dnsrr` mode instead returns the individual task IPs for client-side balancing.$dca$, $dca$[{"url":"https://docs.docker.com/engine/swarm/services/","label":"Docker Docs — Deploy services to a swarm"},{"url":"https://docs.docker.com/engine/network/drivers/overlay/","label":"Docker Docs — Overlay network driver"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$In swarm, a service's default endpoint mode is `vip`. What does that mean for clients resolving the service name?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Networking$dca$, 4, $dca$SINGLE$dca$::"QType", $dca$Containers on different user-defined bridge networks on the same host cannot reach each other by default. How can you let a specific container reach both?$dca$, $dca$[{"id":"a","text":"It is impossible without host networking."},{"id":"b","text":"Attach that container to both networks with docker network connect (multi-homing)."},{"id":"c","text":"Delete one of the networks."},{"id":"d","text":"Publish every container port with -p."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$User-defined bridge networks are isolated from each other; connecting a container to multiple networks (`docker network connect`) lets it communicate on both. Host networking or publishing ports are broader/less precise and not required.$dca$, $dca$[{"url":"https://docs.docker.com/engine/network/drivers/bridge/","label":"Docker Docs — Bridge network driver"},{"url":"https://docs.docker.com/engine/network/","label":"Docker Docs — Networking overview"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Containers on different user-defined bridge networks on the same host cannot reach each other by default. How can you let a specific container reach both?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Security$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Which `docker run` flag adds a single Linux capability (e.g. NET_ADMIN) without granting all of them?$dca$, $dca$[{"id":"a","text":"--cap-add NET_ADMIN"},{"id":"b","text":"--privileged NET_ADMIN"},{"id":"c","text":"--add-capability NET_ADMIN"},{"id":"d","text":"--cap NET_ADMIN=on"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`--cap-add NET_ADMIN` grants just that capability on top of the default set (often paired with `--cap-drop ALL`). `--privileged` grants everything; the other flags are not valid.$dca$, $dca$[{"url":"https://docs.docker.com/reference/cli/docker/container/run/#privileged","label":"Docker Docs — Runtime privilege and Linux capabilities"},{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which `docker run` flag adds a single Linux capability (e.g. NET_ADMIN) without granting all of them?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Security$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Which statement about the default Docker seccomp profile is correct?$dca$, $dca$[{"id":"a","text":"It blocks all syscalls, breaking most containers."},{"id":"b","text":"It allows the common syscalls applications need while blocking a set of dangerous ones (e.g. certain kernel/keyring/clock operations)."},{"id":"c","text":"It only applies to privileged containers."},{"id":"d","text":"It encrypts syscall arguments."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$Docker's default seccomp profile is a permissive allowlist that still blocks roughly several dozen dangerous syscalls. It applies to normal containers (a `--privileged` container effectively runs unconfined) and does not encrypt anything.$dca$, $dca$[{"url":"https://docs.docker.com/engine/security/seccomp/","label":"Docker Docs — Seccomp security profiles"},{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which statement about the default Docker seccomp profile is correct?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Security$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$A container only needs to read configuration from a host directory. Which mount option follows least privilege?$dca$, $dca$[{"id":"a","text":"Mount it read-write so the app can also update it."},{"id":"b","text":"Mount it read-only, e.g. -v /etc/app:/etc/app:ro, so a compromised container cannot modify host config."},{"id":"c","text":"Use --privileged so it has full access."},{"id":"d","text":"Bake the config into the image instead of mounting."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$A read-only bind mount (`:ro`) grants exactly the needed read access and prevents tampering with host files — a least-privilege choice. Read-write or `--privileged` grants more than required.$dca$, $dca$[{"url":"https://docs.docker.com/engine/storage/bind-mounts/","label":"Docker Docs — Bind mounts"},{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$A container only needs to read configuration from a host directory. Which mount option follows least privilege?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Security$dca$, 2, $dca$TRUE_FALSE$dca$::"QType", $dca$True or False: Running a container with --privileged is recommended as a default for convenience.$dca$, $dca$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":"Only for databases"},{"id":"d","text":"Only on managers"}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$False. `--privileged` disables most isolation (all capabilities, device access, relaxed seccomp/AppArmor) and should be avoided unless a specific workload truly requires it.$dca$, $dca$[{"url":"https://docs.docker.com/reference/cli/docker/container/run/#privileged","label":"Docker Docs — Runtime privilege and Linux capabilities"},{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$True or False: Running a container with --privileged is recommended as a default for convenience.$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Security$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$How does enabling userns-remap interact with bind mounts/volumes you previously created as host root?$dca$, $dca$[{"id":"a","text":"Nothing changes; permissions are irrelevant."},{"id":"b","text":"Because container UIDs are remapped to a high host UID range, existing root-owned host files may become inaccessible until ownership is adjusted for the remapped range."},{"id":"c","text":"It deletes the existing data."},{"id":"d","text":"It automatically chowns all host paths to the container user."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$userns-remap shifts in-container UIDs to a subordinate host UID range, so files owned by host root may no longer be writable/readable by the remapped container user — a known operational caveat to plan for. Docker does not auto-chown or delete data.$dca$, $dca$[{"url":"https://docs.docker.com/engine/security/userns-remap/","label":"Docker Docs — Isolate containers with a user namespace"},{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$How does enabling userns-remap interact with bind mounts/volumes you previously created as host root?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Security$dca$, 4, $dca$MULTI$dca$::"QType", $dca$Select ALL true statements about Docker daemon attack surface.$dca$, $dca$[{"id":"a","text":"Exposing the daemon on tcp://0.0.0.0:2375 with no TLS allows remote root-equivalent control."},{"id":"b","text":"TLS mutual authentication should protect any TCP-exposed daemon (port 2376)."},{"id":"c","text":"Unix socket access (or docker group membership) is effectively root on the host."},{"id":"d","text":"The Docker API enforces per-command Linux user permissions automatically."}]$dca$::jsonb, $dca$["a","b","c"]$dca$::jsonb, $dca$An unauthenticated TCP daemon, socket access, and docker-group membership are all root-equivalent; TCP exposure must use mutual TLS on 2376. The API does not apply OS-user-level authorization per command, so D is false.$dca$, $dca$[{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"},{"url":"https://docs.docker.com/engine/daemon/","label":"Docker Docs — Docker daemon configuration file"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Select ALL true statements about Docker daemon attack surface.$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Security$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$What does `docker scout cves <image>` (or an equivalent scanner) report?$dca$, $dca$[{"id":"a","text":"Whether the image is digitally signed."},{"id":"b","text":"Known CVE vulnerabilities found in the image's OS packages and language dependencies, so you can remediate them."},{"id":"c","text":"The container's live syscall activity."},{"id":"d","text":"The swarm Raft health."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$Image scanning enumerates known CVEs in the image contents to drive patching/upgrades. Signing is content trust, syscall monitoring is runtime tooling/seccomp, and Raft health is a swarm concern — all distinct.$dca$, $dca$[{"url":"https://docs.docker.com/engine/security/","label":"Docker Docs — Docker engine security"},{"url":"https://docs.docker.com/engine/security/trust/","label":"Docker Docs — Content trust"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$What does `docker scout cves <image>` (or an equivalent scanner) report?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Storage and Volumes$dca$, 2, $dca$SINGLE$dca$::"QType", $dca$Which command shows detailed information about the volume `dbdata`, including its mountpoint on the host?$dca$, $dca$[{"id":"a","text":"docker volume inspect dbdata"},{"id":"b","text":"docker volume show dbdata"},{"id":"c","text":"docker inspect volume dbdata"},{"id":"d","text":"docker volume detail dbdata"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$`docker volume inspect dbdata` returns the driver, labels, and host `Mountpoint`. The other forms are not valid Docker CLI syntax.$dca$, $dca$[{"url":"https://docs.docker.com/engine/storage/volumes/","label":"Docker Docs — Volumes"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which command shows detailed information about the volume `dbdata`, including its mountpoint on the host?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Storage and Volumes$dca$, 3, $dca$SINGLE$dca$::"QType", $dca$Which approach reliably backs up the data in a named volume `dbdata`?$dca$, $dca$[{"id":"a","text":"Copy /var/lib/docker directly while the daemon runs."},{"id":"b","text":"Run a helper container that mounts the volume and tars its contents to a bind-mounted host path (docker run --rm -v dbdata:/data -v $PWD:/backup ... tar ...)."},{"id":"c","text":"Use docker commit on the volume."},{"id":"d","text":"docker volume export dbdata > backup.tar"}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$The supported pattern is a throwaway container that mounts the volume and the backup destination and archives the data; this works across drivers. Touching `/var/lib/docker` live is unsafe, `docker commit` snapshots containers not volumes, and `docker volume export` is not a command.$dca$, $dca$[{"url":"https://docs.docker.com/engine/storage/volumes/","label":"Docker Docs — Volumes"},{"url":"https://docs.docker.com/engine/storage/bind-mounts/","label":"Docker Docs — Bind mounts"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which approach reliably backs up the data in a named volume `dbdata`?$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Storage and Volumes$dca$, 3, $dca$TRUE_FALSE$dca$::"QType", $dca$True or False: Anonymous volumes (created when no name is given, e.g. -v /data) can be removed by docker volume prune once no container references them.$dca$, $dca$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":"Only named volumes can be pruned"},{"id":"d","text":"Volumes can never be pruned"}]$dca$::jsonb, $dca$["a"]$dca$::jsonb, $dca$True. Anonymous (and unused named) volumes not referenced by any container are removed by `docker volume prune`; this is why important data should use clearly named volumes and be backed up.$dca$, $dca$[{"url":"https://docs.docker.com/engine/storage/volumes/","label":"Docker Docs — Volumes"},{"url":"https://docs.docker.com/reference/cli/docker/","label":"Docker Docs — Docker CLI reference"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$True or False: Anonymous volumes (created when no name is given, e.g. -v /data) can be removed by docker volume prune once no container references them.$dca$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $dca$Storage and Volumes$dca$, 4, $dca$SINGLE$dca$::"QType", $dca$Which statement best describes the relationship between storage drivers (overlay2) and volumes?$dca$, $dca$[{"id":"a","text":"Volumes use the storage driver's copy-on-write for all writes."},{"id":"b","text":"The storage driver manages the image/container layered filesystem (copy-on-write), while volumes bypass it to give better, persistent I/O for application data."},{"id":"c","text":"They are the same subsystem."},{"id":"d","text":"Volumes only work with the vfs driver."}]$dca$::jsonb, $dca$["b"]$dca$::jsonb, $dca$The storage driver (e.g. overlay2) handles the layered, copy-on-write container filesystem; volumes write outside that layer for persistence and to avoid copy-up overhead — recommended for databases and write-heavy data. Volumes work regardless of the storage driver.$dca$, $dca$[{"url":"https://docs.docker.com/engine/storage/drivers/","label":"Docker Docs — Storage drivers"},{"url":"https://docs.docker.com/engine/storage/volumes/","label":"Docker Docs — Volumes"}]$dca$::jsonb, $dca$PUBLISHED$dca$::"QStatus", $dca$manual:dca-seed$dca$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $dca$DCA-P3$dca$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $dca$Which statement best describes the relationship between storage drivers (overlay2) and volumes?$dca$);
